insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('bpmw-m-schrumpfschlauch-mastik-korrosion','schrumpfschlauch','BPMW M','Schrumpfschlauch, mittelwandig, aus Polyolefin mit Mastikbeschichtung','BPMW M · Polyolefin','BPMW M ist ein mittelwandiger Schrumpfschlauch aus Polyolefin mit Mastikbeschichtung. Der BPMW M ist besonders gut geeignet zur nachträglichen Umhüllung von Schweißnähten bei Metallrohrverbindungen. Durch die Masticbeschichtung bietet er einen hervorragenden Schutz vor Feuchtigkeit und Wasser.','Polyolefin','-35 °C bis 110 °C','Meter',ARRAY['Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm','Ø 120 mm','Ø 150 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Hohe elektrische Isolierung','Hoher mechan. Schutz','Mittelwandig','UV-beständig']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"hohe elektrische Isolierung, hoher mechan. Schutz, mittelwandig, UV-beständig"},{"label":"Betriebstemperatur min.","value":"-35 °C"},{"label":"Betriebstemperatur max.","value":"110 °C"},{"label":"Durchmesser innen von (mm)","value":"30.0"},{"label":"Durchmesser innen bis (mm)","value":"350,0"},{"label":"Schrumpfrate","value":"3:1"},{"label":"Schrumpftemperatur","value":"120 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2022/12/BPMW-M.pdf','/bit/products/bpmw-m-schrumpfschlauch-mastik-korrosion.jpg','Schrumpfschlauch, mittelwandig, aus Polyolefin mit Mastikbeschichtung','published',2) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors