insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('bptm','schrumpfschlauch','BPTM','Schrumpfschlauch für Stromsammelschienen','BPTM · Polyolefin','BPTM wird aus strahlenvernetzten, halogenfreien Verbindungen hergestellt. Speziell entwickelte Formulierung verleiht dem Schlauch hervorragende elektrische, schrumpfende und Anti-Tracking-Eigenschaften.','Polyolefin','-40 °C bis 105 °C','Meter',ARRAY['Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm','Ø 120 mm','Ø 150 mm']::text[],ARRAY['Braun']::text[],ARRAY['Halogenfrei','Mittelwandig']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"halogenfrei, mittelwandig"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"105 °C"},{"label":"Durchmesser innen von (mm)","value":"15"},{"label":"Durchmesser innen bis (mm)","value":"265"},{"label":"Schrumpfrate","value":"2.5:1"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2026/05/BPTM.pdf','/bit/products/bptm.jpg','Schrumpfschlauch für Stromsammelschienen','published',3) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
