insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('dr-dieselbestaendiger-schrumpfschlauch-ber-100-elastomer','schrumpfschlauch','BER 100','Dieselbeständiger Schrumpfschlauch aus vernetztem Elastomer','BER 100 · Elastomer','Der BER 100 ist ein flexibler, mittelwandiger Schrumpfschlauch auf Elastomerbasis. Aufgrund seiner Beständigkeit gegen Diesel, Kraftstoffe, hydraulische Flüssigkeiten und Schmieröle eignet sich BER 100 hervorragend für den thermischen und chemischen Schutz von Bauteilen.','Elastomer','-55 °C bis +150 °C','Meter',ARRAY['Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Mittelwandig','Schwer entflammbar','Selbstverlöschend']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Elastomer"},{"label":"Besonderheiten","value":"mittelwandig, schwer entflammbar, selbstverlöschend"},{"label":"Betriebstemperatur min.","value":"-55 °C"},{"label":"Betriebstemperatur max.","value":"+150 °C"},{"label":"Durchmesser innen von (mm)","value":"3,20"},{"label":"Durchmesser innen bis (mm)","value":"97,00"},{"label":"Schrumpfrate","value":"2:1"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BER-100-5.pdf','/bit/products/dr-dieselbestaendiger-schrumpfschlauch-ber-100-elastomer.webp','DR diesel resistant heatshrink tube','published',5) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications