insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('dualschrumpfschlauch-ptfe-fep','schrumpfschlauch','PTFE/FEP','Dualschrumpfschlauch aus PTFE/FEP','PTFE/FEP · PTFE/FEP','Dualschrumpfschlauch aus PTFE mit Inlay aus FEP. Er dient zur luft- und feuchtigkeitsdichten Verbindung von Kabeln und Leitungen und bietet dabei einen effektiven Schutz gegen aggressive Medien und hohen Temperaturen. Dual-Schrumpfschlauch PTFE/FEP – Ihre zuverlässige Lösung für mediendichte Abschlüsse und wasserdichte Verbindungen. Ideal geeignet für den Schutz von Sonden, Thermofühlern oder Sensoren. Der äußere Schrumpfschlauch, hergestellt aus robustem PTFE , besticht durch seine erhöhte Temperaturresistenz von +260°C. Der innere Schlauch, aus hochwertigem FEP, dient beim Aufschrumpfen als eine Art Schmelzkleber. Unsere Standardversion der Dual-Schrumpfschläuche hat eine Länge von 1,22 m und ist bereits vorgeschrumpft. Je nach Ihren Anforderungen bieten wir auch Sonderlängen an. Neben der Standardausführung gibt es die Dualschrumpfschläuche auch in der dünnwandigen Ausführung PTFE/FEP LW','PTFE/FEP','-67 °C bis +205 °C','Meter',ARRAY['Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm']::text[],ARRAY['Transparent']::text[],ARRAY['Antiadhäsiv','Dualschrumpfschlauch','Hohe chemische Beständigkeit','Hohe Temperaturbeständigkeit','Unbrennbar']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"PTFE/FEP"},{"label":"Besonderheiten","value":"antiadhäsiv, Dualschrumpfschlauch, hohe chemische Beständigkeit, hohe Temperaturbeständigkeit, unbrennbar"},{"label":"Betriebstemperatur min.","value":"-67 °C"},{"label":"Betriebstemperatur max.","value":"+205 °C"},{"label":"Durchmesser innen von (mm)","value":"0,91"},{"label":"Durchmesser innen bis (mm)","value":"25,40"},{"label":"Schrumpfrate","value":"2:1"},{"label":"Schrumpftemperatur","value":"327 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2023/11/PTFE_FEP.pdf','/bit/products/dualschrumpfschlauch-ptfe-fep.jpg','Dualschrumpfschlauch aus PTFE/FEP','published',6) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('fep-200-ul-schrumpfschlaeuche','schrumpfschlauch','FEP 200 UL','FEP 200 UL – halbsteifer, hochtransparenter, abriebfester Schrumpfschlauch.','FEP 200 UL · FEP','Der FEP 200 UL hat eine ausgezeichnete Hochtemperaturbeständigkeit, Säurebeständigkeit und Antihaftwirkung. Das Material ist weit verbreitet in der Luft- und Raumfahrt, der Medizintechnik und anderen Bereichen. Es ist zugelassen nach UL 224.','FEP','-55 °C bis +200 °C','Meter',ARRAY['Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm']::text[],ARRAY['Transparent']::text[],ARRAY['Hohe Temperaturbeständigkeit','Säurebeständig','UL-zugelassen','Zulassung: UL 224']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"FEP"},{"label":"Besonderheiten","value":"hohe Temperaturbeständigkeit, säurebeständig, UL-zugelassen"},{"label":"Zulassung","value":"UL 224"},{"label":"Betriebstemperatur min.","value":"-55 °C"},{"label":"Betriebstemperatur max.","value":"+200 °C"},{"label":"Durchmesser innen von (mm)","value":"1,95"},{"label":"Durchmesser innen bis (mm)","value":"14,30"},{"label":"Schrumpfrate","value":"1.3:1"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2023/05/FEP-200-UL-3.pdf','/bit/products/fep-200-ul-schrumpfschlaeuche.jpg','FEP Schlauch','published',7) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('gewebeschrumpfschlauch-bp-hsf-125','schrumpfschlauch','BP HSF 125','Vorteile im Detail:','BP HSF 125 · Polyester- und Polyolefinfasern','Produktbeschreibung Der Gewebeschrumpfschlauch BP HSF 125 ist ein halogenfreier Schrumpfschlauch aus hochwertigen Polyester- und Polyolefinfasern. Er bietet exzellenten mechanischen Abriebschutz und reduziert Vibrationen, was ihn ideal für zahlreiche industrielle Anwendungen macht. Das Gewebe hat ein hervorragendes Schrumpfverhalten und passt sich optimal an das umschrumpfte Objekt an. Halogenfreie Materialien für sichere und umweltfreundliche Anwendungen Exzellenter mechanischer Abriebschutz Reduziert Vibrationen und schützt empfindliche Komponenten Sehr gutes Schrumpfverhalten und hohe mechanische Festigkeit Flexibel und ideal für enge Anwendungen Produktanwendung Der Gewebeschrumpfschlauch BP HSF 125 schützt zuverlässig vor mechanischem Abrieb und sorgt für zusätzlichen Schutz in verschiedenen Bereichen. Zu den typischen Einsatzgebieten gehören: Schutz vor mechanischem Abrieb an Kabelbäumen Klapperschutz im Motorraum von Fahrzeugen Schutz von Hydraulikleitungen Mechanischer Schutz von Ölleitungen Vielseitig einsetzbar in anderen Anwendungen, bei denen Flexibilität und Abriebschutz gefragt sind Technische Details Material Polyester- und Polyolefinfasern Halogenfrei Ja Durchmesser (vor dem Schrumpfen) 6,0 mm bis 80,0 mm, Sonderausführungen bis 110 mm Schrumpfverhältnis 2:1 Maximale Betriebstemperatur +125°C Minimale Schrumpftemperatur +110°C FAQs – Häufig gestellte Fragen Was ist der Unterschied zwischen einem Gewebeschrumpfschlauch und einem herkömmlichen Schrumpfschlauch? Ein Gewebeschrumpfschlauch bietet einen ausgezeichneten mechanischen Schutz vor Abrieb und Vibrationen. Wie wird der BP HSF 125 Gewebeschrumpfschlauch montiert? Der Gewebeschrumpfschlauch wird einfach über das zu schützende Objekt geschoben und dann mit einer Heißluftpistole oder einem anderen geeigneten Schrumpfwerkzeug erhitzt, bis er sich vollständig um das Objekt zieht und fest sitzt. Für welche Anwendungen eignet sich der BP HSF 125 Schrumpfschlauch? Der BP HSF 125 Schrumpfschlauch eignet sich für Kabelschutz, den Schutz von Hydraulikleitungen, Ölleitungen und für alle Anwendungen, bei denen Abrieb- und Vibrationsschutz erforderlich sind. Besonders geeignet ist er für den Einsatz in Fahrzeugen und Maschinen.','Polyester- und Polyolefinfasern','-40 °C bis 125 °C','Meter',ARRAY['Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Flammhemmend','Gewebe','Halogenfrei']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Polyester- und Polyolefinfasern"},{"label":"Besonderheiten","value":"flammhemmend, Gewebe, halogenfrei"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"125 °C"},{"label":"Durchmesser innen von (mm)","value":"6,00"},{"label":"Durchmesser innen bis (mm)","value":"80,00"},{"label":"Schrumpfrate","value":"2:1"},{"label":"Schrumpftemperatur","value":"110 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BP-HSF-125-3.pdf','/bit/products/gewebeschrumpfschlauch-bp-hsf-125.jpg','Gewebeschrumpfschlauch','published',8) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image