insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('hart-pvc-schrumpfschlauch','schrumpfschlauch','HPS','Hart PVC Schrumpfschlauch','HPS · Hart-PVC','Sehr dünnwandiger Schrumpfschlauch, ideal zur Konfektionierung von Akkupacks. HPS wird in einer flachgewalzten Ausführung geliefert. Die Bestellbezeichnung richtet sich daher nach flacher Breite, gewünschter Wandstärke und Farbe.','Hart-PVC','-20 °C bis +85 °C','Meter',ARRAY['Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm','Ø 120 mm','Ø 150 mm']::text[],ARRAY['Schwarz','Rot','Weiß','Blau','Gelb','Grün','Transparent','Andere auf Anfrage']::text[],ARRAY['Dünnwandig','Flammhemmend','Zulassung: UL 224 VW-1 auf Nachfrage möglich']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Hart-PVC"},{"label":"Besonderheiten","value":"dünnwandig, flammhemmend"},{"label":"Zulassung","value":"UL 224 VW-1 auf Nachfrage möglich"},{"label":"Betriebstemperatur min.","value":"-20 °C"},{"label":"Betriebstemperatur max.","value":"+85 °C"},{"label":"Durchmesser innen von (mm)","value":"2,50"},{"label":"Durchmesser innen bis (mm)","value":"220,00"},{"label":"Schrumpfrate","value":"2:1"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/HPS.pdf','/bit/products/hart-pvc-schrumpfschlauch.jpg','Hart PVC Schrumpfschlauch','published',9) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('hv-schrumpfschlauch-1000v','schrumpfschlauch','BP 125 HV','BP 125 HV','Polyolefin','Der BP 125 HV ist ein flexibler Wärmeschrumpfschlauch aus modifiziertem Polyolefin. Das Material ist ideal für die Verwendung in E-Autos geeignet.','Polyolefin','-55 °C bis 125 °C','Meter',ARRAY['Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm']::text[],ARRAY['Orange']::text[],ARRAY['1000V','Flammhemmend','Zulassung: UL 224']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"1000V, flammhemmend"},{"label":"Zulassung","value":"UL 224"},{"label":"Betriebstemperatur min.","value":"-55 °C"},{"label":"Betriebstemperatur max.","value":"125 °C"},{"label":"Durchmesser innen von (mm)","value":"15,0"},{"label":"Durchmesser innen bis (mm)","value":"45,0"},{"label":"Schrumpfrate","value":"2:1"},{"label":"Schrumpftemperatur","value":"90 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2023/12/BP-125-HV-12112025.pdf','/bit/products/hv-schrumpfschlauch-1000v.jpg','bp 125 HV - 1000V Schrumpfschlauch','published',10) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('kaltschrumpfschlauch-aus-silikon','schrumpfschlauch','BHW CS','BHW CS','VMQ (Silikon)','Unser Kaltschrumpfschlauch aus Silikon eignet sich ideal für eine schnelle und sichere elektrische Isolierung ohne Hitzeeinwirkung. Er überzeugt durch seine hohe Elastizität , thermische Beständigkeit und einfache Handhabung. Besonders in anspruchsvollen industriellen Umgebungen bietet dieser Schrumpfschlauch eine zuverlässige Lösung zur Kabel- und Steckerverdichtung. Eigenschaften & Vorteile Material: Hochwertiges, widerstandsfähiges Silikon Temperaturbereich: –60 °C bis +90 °C Selbstverschließend durch Rückstellkraft – kein Erhitzen notwendig Ideal für Reparaturen, Isolation, Abdichtung und mechanischen Schutz Einfache Montage – spart Zeit und Werkzeug Resistent gegen Feuchtigkeit, Ozon und UV-Strahlung Anwendungsgebiete Der Kaltschrumpfschlauch kommt überall dort zum Einsatz, wo Kabel und Verbindungen schnell und sicher geschützt werden müssen – ohne Schrumpfpistole oder offene Flamme. Typische Einsatzbereiche: Elektroinstallation Industrie- und Maschinenbau Fahrzeugtechnik Solar- und Photovoltaikanlagen Antennentechnik Kaltschrumpfschlauch kaufen bei BIT GmbH Vertrauen Sie auf unsere langjährige Erfahrung im Bereich Spezialschläuche und Isoliertechnik . Wir bieten Ihnen Kaltschrumpfschläuche in verschiedenen Abmessungen und Verpackungseinheiten. Gerne beraten wir Sie individuell. Jetzt Kontakt aufnehmen oder direkt Angebot anfordern ! FAQ – Häufige Fragen zum Kaltschrumpfschlauch Wie funktioniert ein Kaltschrumpfschlauch? Der Kaltschrumpfschlauch wird vorgedehnt auf einem Träger geliefert. Nach dem Positionieren auf der zu schützenden Stelle wird der Träger entfernt – der Schlauch zieht sich automatisch zusammen und dichtet ab. Worin unterscheidet sich der Kaltschrumpfschlauch vom Warmschrumpfschlauch? Im Gegensatz zum Warmschrumpfschlauch benötigt der Kaltschrumpfschlauch keine Hitzequelle wie Heißluft – ideal bei schwer zugänglichen Stellen oder in sensiblen Bereichen.','VMQ (Silikon)','-60 °C bis 90 °C','Meter',ARRAY['Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm']::text[],ARRAY['Schwarz','Grau']::text[],ARRAY['Kaltschrumpfschlauch']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"VMQ (Silikon)"},{"label":"Besonderheiten","value":"Kaltschrumpfschlauch"},{"label":"Betriebstemperatur min.","value":"-60 °C"},{"label":"Betriebstemperatur max.","value":"90 °C"},{"label":"Durchmesser innen von (mm)","value":"20,00"},{"label":"Durchmesser innen bis (mm)","value":"104,00"},{"label":"Schrumpfrate","value":"2:1"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BHW-CS-5.pdf','/bit/products/kaltschrumpfschlauch-aus-silikon.jpg','Kaltschrumpfschlauch aus Silikon - BIT Bierther GmbH','published',11) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('peek-schrumpfschlauch','schrumpfschlauch','PEEK Schrumpfschlauch','PEEK Schrumpfschlauch','PEEK','PEEK Schrumpfschlauch ist ideal für anspruchsvolle Umgebungen, in denen Abrieb, hoher Druck, Chemikalien, Wasser oder dielektrische Störungen eine Gefahr für Drähte und elektrische Komponenten darstellen. Anwendungen: – Isolierung elektrischer Komponenten – Schutz von medizinischen Geräten – Verkapselung und Isolierung von Drähten und Kabeln','PEEK','-65 °C bis +260 °C','Meter',ARRAY['Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm']::text[],ARRAY['Natur','Andere auf Anfrage']::text[],ARRAY['Abriebfest','Hohe chemische Beständigkeit','Hohe Temperaturbeständigkeit']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"PEEK"},{"label":"Besonderheiten","value":"abriebfest, hohe chemische Beständigkeit, hohe Temperaturbeständigkeit"},{"label":"Betriebstemperatur min.","value":"-65 °C"},{"label":"Betriebstemperatur max.","value":"+260 °C"},{"label":"Durchmesser innen von (mm)","value":"0,965"},{"label":"Durchmesser innen bis (mm)","value":"9,957"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2024/02/PEEK-2.pdf','/bit/products/peek-schrumpfschlauch.png','PEEK Schrumpfschlauch','published',12) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('reparaturmanschette-bwas','schrumpfschlauch','BWAS','Wärmeschrumpfende Reparaturmanschette mit Innenkleber','BWAS · Polyolefin','Die wärmeschrumpfende Reparaturmanschette BWAS ist hervorragend für schnelle und einfache Reparaturen beschädigter Kabel und Rohre geeignet. Durch die kleberbeschichtete Innenseite bietet sie eine sichere Abdichtung gegen Feuchtigkeit und Korrosion.','Polyolefin','-40 °C bis +65 °C','Meter',ARRAY['Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm','Ø 120 mm','Ø 150 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Schrumpfmanschette']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"Schrumpfmanschette"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"+65 °C"},{"label":"Durchmesser innen von (mm)","value":"34,00"},{"label":"Durchmesser innen bis (mm)","value":"200,00"},{"label":"Schrumpfrate","value":"3:1"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BWAS-1.pdf','/bit/products/reparaturmanschette-bwas.webp','Reparaturmanschette','published',13) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpfschlauch-4-1','schrumpfschlauch','BPDW 104','Schrumpfschlauch mit Kleber, Schrumpfrate 4:1','BPDW 104 · Polyolefin','BPDW 104 ist ein flexibler Schrumpfschlauch aus Polyolefin und mit einer Schrumpfrate von 4:1, beschichtet mit einem thermoplastischen Spezialkleber. Durch das hohe Schrumpfverhältnis lassen sich auch große Durchmesserunterschiede, z.B. von Stecker zu Kabel, gut abdecken. Das Material ist in vielen Abmessungen direkt ab Lager verfügbar und kann auch als fertiger Zuschnitt hergestellt werden.','Polyolefin','-55 °C bis 125 °C','Meter',ARRAY['Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm']::text[],ARRAY['Schwarz','Transparent','Andere auf Anfrage']::text[],ARRAY['Flammhemmend','Hohes Schrumpfverhältnis','Kleberbeschichtet','Schwer entflammbar','UL-zugelassen','Zulassung: UL 224 (außer transparent)']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"flammhemmend, hohes Schrumpfverhältnis, kleberbeschichtet, schwer entflammbar, UL-zugelassen"},{"label":"Zulassung","value":"UL 224 (außer transparent)"},{"label":"Betriebstemperatur min.","value":"-55 °C"},{"label":"Betriebstemperatur max.","value":"125 °C"},{"label":"Durchmesser innen von (mm)","value":"4,00"},{"label":"Durchmesser innen bis (mm)","value":"52,00"},{"label":"Schrumpfrate","value":"4:1"},{"label":"Schrumpftemperatur","value":"110 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BPDW-104-6.pdf','/bit/products/schrumpfschlauch-4-1.webp','Schrumpfschlauch mit Kleber, Schrumpfrate 4:1','published',14) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpfschlauch-5-zu-1-mit-innenkleber','schrumpfschlauch','BPBK','Schrumpfschlauch 5:1 mit Innenkleber, perfekt zur Abdichtung von Kabelbäumen','BPBK · Polyolefin','Modifizierter Schrumpfschlauch mit sehr hoher Schrumpfrate von ca. 5:1 und thermoplastischem Innenkleber. Dieser Schrumpfschlauch aus Polyolefin mit Innenkleber eignet sich hervorragend zur Abdichtung und Isolierung von Kabelbäumen, Kabeln und Leitungen. Durch die hohe Schrumpfrate von ca. 5:1 ist er besonders gut für Anwendungen mit großen Durchmesserunterschieden geeignet. Der thermoplastische Innenkleber dichtet besonders gut ab. Durch seine sehr gute chemische Beständigkeit sowie die hervorragenden mechanischen und elektrischen Eigenschaften kommt dieser Schrumpfschlauch häufig in der Automobilindustrie zum Einsatz. Technische Daten: Material: Polyolefin, kleberbeschichtet Schrumpfrate ca. 5:1 Einsatztemp. Min.: -40°C Einsatztemp. Max.: +125°C Schrumpftemperatur Min.: +110°C Brennbarkeit: schwer entflammbar Längsschrumpf: +-10% max. Zugfestigkeit: >10,4 MPa Durchschlagsfestigkeit: >19,7 kV/mm Kleberbeschichtung','Polyolefin','-40 °C bis 125 °C','Meter',ARRAY['Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm']::text[],ARRAY['Schwarz','Transparent']::text[],ARRAY['Flammhemmend','Kleberbeschichtet','Schwer entflammbar','UL-zugelassen','Zulassung: UL 224 (nur schwarz)']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"flammhemmend, kleberbeschichtet, schwer entflammbar, UL-zugelassen"},{"label":"Zulassung","value":"UL 224 (nur schwarz)"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"125 °C"},{"label":"Durchmesser innen von (mm)","value":"5,70"},{"label":"Durchmesser innen bis (mm)","value":"17,80"},{"label":"Schrumpfrate","value":"5:1"},{"label":"Schrumpftemperatur","value":"110 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BPBK-5.pdf','/bit/products/schrumpfschlauch-5-zu-1-mit-innenkleber.jpg','Schrumpfschlauch 5:1 mit Innenkleber, perfekt zur Abdichtung von Kabelbäumen','published',15) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpfschlauch-61-bphw-a','schrumpfschlauch','BPHW A','Dickwandiger Schrumpfschlauch mit Kleber, Schrumpfrate 6:1','BPHW A · Polyolefin','Der BPHW A ist ein dickwandiger Schrumpfschlauch mit extra großem Schrumpfvermögen (6:1) und Beschichtung mit Schmelzkleber. Eigenschaften: Dickwandige Konstruktion: Der BPHW A Schrumpfschlauch bietet dank seiner dicken Wand eine herausragende Robustheit. Dies gewährleistet einen optimalen Schutz für Kabel und Verbindungen gegen mechanische Einwirkungen, Abrieb und andere äußere Einflüsse. Hohe Schrumpfrate von 6:1: Mit einer sehr hohen Schrumpfrate von 6:1 kann sich der Schlauch auf ein Sechstel seiner ursprünglichen Größe reduzieren und ermöglicht die Ummantelung von großen DUrchmesserunterschieden. Schmelzkleber-Beschichtung: Dieser Schrumpfschlauch verfügt über eine spezielle Schmelzkleber-Beschichtung. Während des Schrumpfprozesses schmilzt dieser Kleber, wodurch eine feste und wasserabweisende Abdichtung entsteht. Dies bietet zusätzlichen Schutz gegen Feuchtigkeit. Anwendungen: Der BPHW A eignet sich ideal für die sichere Ummantelung von Kabelverbindungen, elektronischen Bauteilen, Steckern und anderen Anwendungen, bei denen sowohl mechanischer Schutz als auch Feuchtigkeitsbeständigkeit erforderlich sind. Dank seiner hohen Schrumpfrate und Klebereigenschaften ist er besonders in anspruchsvollen Umgebungen und für spezialisierte Anwendungen geeignet.','Polyolefin','-55 °C bis 110 °C','Meter',ARRAY['Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm','Ø 120 mm','Ø 150 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Dickwandig','Hohes Schrumpfverhältnis','Kleberbeschichtet']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"dickwandig, hohes Schrumpfverhältnis, kleberbeschichtet"},{"label":"Betriebstemperatur min.","value":"-55 °C"},{"label":"Betriebstemperatur max.","value":"110 °C"},{"label":"Durchmesser innen von (mm)","value":"19,00"},{"label":"Durchmesser innen bis (mm)","value":"235,00"},{"label":"Schrumpfrate","value":"6:1"},{"label":"Schrumpftemperatur","value":"120 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BPHW-A-2.pdf','/bit/products/schrumpfschlauch-61-bphw-a.jpg','hohe Schrumpfrate','published',16) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
