insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpfschlauch-dickwandig-bptw-a','schrumpfschlauch','BPTW A','Schrumpfschlauch, dickwandig mit Kleber','BPTW A · Polyolefin','Der BPTW A ist ein dickwandiger Schrumpfschlauch aus Polyolefin mit Kleberbeschichtung. Durch die hohe Wandstärke und den Schmelzkleber verfügt er über sehr gute mechanische Eigenschaften. Die Kleberbeschichtung sorgt für eine hervorragende Abdichtung und Isolierung. Der dickwandige Schrumpfschlauch BPTW A überzeugt zudem durch eine sehr gute UV-Beständigkeit.','Polyolefin','-55 °C bis 110 °C','Meter',ARRAY['Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm','Ø 120 mm','Ø 150 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Dickwandig','Hohes Schrumpfverhältnis','Kleberbeschichtet','UV-beständig']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"dickwandig, hohes Schrumpfverhältnis, kleberbeschichtet, UV-beständig"},{"label":"Betriebstemperatur min.","value":"-55 °C"},{"label":"Betriebstemperatur max.","value":"110 °C"},{"label":"Durchmesser innen von (mm)","value":"9,00"},{"label":"Durchmesser innen bis (mm)","value":"350,00"},{"label":"Schrumpfrate","value":"3:1"},{"label":"Schrumpftemperatur","value":"120 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BPTW-A-1.pdf','/bit/products/schrumpfschlauch-dickwandig-bptw-a.webp','Schrumpfschlauch mittelwandig','published',29) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,si