insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpfschlauch-gruen-gelb','schrumpfschlauch','BP 135 GE/GR','Schrumpfschlauch grün-gelb, aus vernetztem Polyolefin','BP 135 GE/GR · Polyolefin','Der BP 135 GE/GR ist ein grün-gelb gestreifter Schrumpfschlauch aus Polyolefin, der sich besonders zum Schutz, zur Kennzeichnung und zur Isolierung von Erdungskabeln eignet. Das Material ist beständig bis +135°C und zugelassen nach UL 224 (E196690) Als grün-gelben Schrumpfschlauch mit einem höheren Schrumpfverhältnis von 3:1 bieten wir unseren BP 300 an. Grün-gelb gestreifter, flexibler Schrumpfschlauch mit einem Schrumpfverhältnis von 2:1. Flexibel Grün-gelbe Farbkombination gemäß der internationalen Kennzeichnung elektrischer Erdung Beständig gegenüber vielen Flüssigkeiten und Lösungsmitteln Schrumpfrate: 2:1 Dauereinsatztemperatur: -55°C bis 135°C','Polyolefin','-55 °C bis 135 °C','Meter',ARRAY['Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm']::text[],ARRAY['Grün-Gelb']::text[],ARRAY['Dünnwandig','Flammhemmend','Flexibel','Halogenfrei','UL-zugelassen','Zulassung: UL 224']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"dünnwandig, flammhemmend, flexibel, halogenfrei, UL-zugelassen"},{"label":"Zulassung","value":"UL 224"},{"label":"Betriebstemperatur min.","value":"-55 °C"},{"label":"Betriebstemperatur max.","value":"135 °C"},{"label":"Durchmesser innen von (mm)","value":"1,20"},{"label":"Durchmesser innen bis (mm)","value":"101,60"},{"label":"Schrumpfrate","value":"2:1"},{"label":"Schrumpftemperatur","value":"90 °C"}]'::jso