2:1"},{"label":"Schrumpftemperatur","value":"110 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BPDW-102-5.pdf','/bit/products/schrumpfschlauch-mit-kleber-bpdw-102.webp','Schrumpfschlauch mit Kleber, Schrumpfrate 2:1','published',36) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
