insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpfschlauch-ptfe-200-awg','schrumpfschlauch','PTFE 200 AWG','PTFE 200 AWG – Schrumpfschlauch aus PTFE, Schrumpfrate 2:1','PTFE 200 AWG · PTFE','PTFE 200 ist ein halbsteifer Schrumpfschlauch aus PTFE mit einer Schrumpfrate von 2:1 und einer Auswahl verschiedener Wandstärken. Hohe chemische, mechanische und thermische Belastbarkeit zeichnen dieses Material aus.','PTFE','-67 °C bis 260 °C','Meter',ARRAY['Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm']::text[],ARRAY['Transparent','Andere auf Anfrage']::text[],ARRAY['Antiadhäsiv','Dünnwandig','Hohe chemische Beständigkeit','Hohe Temperaturbeständigkeit','Unbrennbar']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"PTFE"},{"label":"Besonderheiten","value":"antiadhäsiv, dünnwandig, hohe chemische Beständigkeit, hohe Temperaturbeständigkeit, unbrennbar"},{"label":"Betriebstemperatur min.","value":"-67 °C"},{"label":"Betriebstemperatur max.","value":"260 °C"},{"label":"Durchmesser innen von (mm)","value":"0,60"},{"label":"Durchmesser innen bis (mm)","value":"11,95"},{"label":"Schrumpfrate","value":"2:1"},{"label":"Schrumpftemperatur","value":"327 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/PTFE-200-AWG-2.pdf','/bit/products/schrumpfschlauch-ptfe-200-awg.jpg','Schrumpfschlauch aus PTFE','published',38) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.application