insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpfschlauch-ptfe-400-teflon-4-1','schrumpfschlauch','PTFE 400','PTFE 400','PTFE','Unser PTFE-Schrumpfschlauch mit einer Schrumpfrate von 4:1 eignet sich perfekt für anspruchsvolle Anwendungen in der Elektrotechnik, Medizintechnik, Automobilindustrie und mehr. Das Material bietet höchste Temperatur- und Chemikalienbeständigkeit. Eigenschaften des PTFE-Schrumpfschlauchs 4:1 Sehr hohe Schrumpfrate Extrem beständig gegenüber aggressiven Chemikalien und Lösungsmitteln Großer Temperaturbereich: –67 °C bis +260 °C Ausgezeichnete Antihaft-Eigenschaften (Antiadhäsion) Gute Verarbeitbarkeit und Dimensionsstabilität REACH- und RoHS-konform Verarbeitungshinweise Optimale Verarbeitungstemperatur: 330–380 °C Erkennbar am Schrumpfvorgang und dem Übergang der Oberfläche von milchig zu transparent. Sicherheitshinweis: Vermeiden Sie Temperaturen über 400 °C! Oberhalb dieser Schwelle beginnt PTFE sich zu zersetzen. Arbeiten Sie stets unter geeigneter Absaugung. Jetzt Angebot für PTFE-Schrumpfschlauch 4:1 anfordern Ob Standardabmessung oder Sonderanfertigung – wir liefern hochwertige PTFE-Schrumpfschläuche mit kurzer Lieferzeit und persönlicher Beratung. Jetzt anfragen','PTFE','-67 °C bis +260 °C','Meter',ARRAY['Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm']::text[],ARRAY['Transparent','Andere auf Anfrage']::text[],ARRAY['Antiadhäsiv','Dünnwandig','Hohe chemische Beständigkeit','Hohe Temperaturbeständigkeit','Sehr hohes Schrumpfverhältnis','Unbrennbar']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"PTFE"},{"label":"Besonderheiten","value":"antiadhäsiv, dünnwandig, hohe chemische Beständigkeit, hohe Temperaturbeständigkeit, sehr hohes Schrumpfverhältnis, unbrennbar"},{"label":"Betriebstemperatur min.","value":"-67 °C"},{"label":"Betriebstemperatur max.","value":"+260 °C"},{"label":"Durchmesser innen von (mm)","value":"1,98"},{"label":"Durchmesser innen bis (mm)","value":"101,60"},{"label":"Schrumpfrate","value":"4:1"},{"label":"Schrumpftemperatur","value":"327 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/PTFE-400-3.pdf','/bit/products/schrumpfschlauch-ptfe-400-teflon-4-1.jpg','PTFE Schrumpfschlauch 4:1','published',39) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpfschlauch-ptfe-fep-lw','schrumpfschlauch','PTFE/FEP-LW','Dualschrumpfschlauch aus PTFE/FEP (dünnwandig)','PTFE/FEP-LW · PTFE/FEP','Dualschrumpfschlauch aus PTFE mit Inlay aus FEP. Er dient zur luft- und feuchtigkeitsdichten Verbindung von Kabeln und Leitungen und bietet dabei einen effektiven Schutz gegen aggressive Medien und hohen Temperaturen.','PTFE/FEP','-67 °C bis 205 °C','Meter',ARRAY['Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm']::text[],ARRAY['Transparent']::text[],ARRAY['Antiadhäsiv','Dualschrumpfschlauch','Dünnwandig','Hohe chemische Beständigkeit','Hohe Temperaturbeständigkeit','Unbrennbar']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"PTFE/FEP"},{"label":"Besonderheiten","value":"antiadhäsiv, Dualschrumpfschlauch, dünnwandig, hohe chemische Beständigkeit, hohe Temperaturbeständigkeit, unbrennbar"},{"label":"Betriebstemperatur min.","value":"-67 °C"},{"label":"Betriebstemperatur max.","value":"205 °C"},{"label":"Durchmesser innen von (mm)","value":"1,65"},{"label":"Durchmesser innen bis (mm)","value":"25,40"},{"label":"Schrumpfrate","value":"2:1"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/06/PTFE_FEP-LW-1.pdf','/bit/products/schrumpfschlauch-ptfe-fep-lw.jpg','Dualschrumpfschlauch aus PTFE/FEP (dünnwandig)','published',40) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded