insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpfschlauch-ultra-duennwandig-bputw','schrumpfschlauch','BPUTW','Ultra dünnwandiger Schrumpfschlauch','BPUTW · Polyolefin','Der BPUTW ist ein ultra dünnwandiger flexibler Schrumpfschlauch aus Polyolefin. Er eignet sich durch seine schnelle Schrumpffähigkeit ausgezeichnet für wärmeempfindliche Anwendungen. Unser Schrumpfschlauch BPUTW zeichnet sich durch seine außergewöhnliche Dünnwandigkeit und Flexibilität aus, was ihn ideal für die Isolierung und den Schutz hochflexibler Kabel macht. Die schnelle Schrumpfung gewährleistet eine effiziente Anwendung. Anpassungsfähiger Schrumpfschlauch für perfekte Ummantelung Unser flexibler Schrumpfschlauch passt sich nahtlos der Kontur des zu ummantelnden Gegenstands an. Eigenschaften unserer BPUTW Serie Hergestellt aus vernetztem Polyolefin Schrumpfrate von ca. 2:1 Ultra dünnwandig Sehr hohe Flexibilität Zulassung nach UL 224 (außer transparent) Temperaturbereich von -55°C bis 125°C Der BPUTW ist perfekt geeignet für anspruchsvolle Anwendungen, bei denen eine besonders geringe Wandstärke und hohe Flexibilität entscheidend sind.','Polyolefin','-55 °C bis 125 °C','Meter',ARRAY['Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm']::text[],ARRAY['Schwarz','Transparent']::text[],ARRAY['Dünnwandig','Flammhemmend','Flexibel','UL-zugelassen','Ultra-dünnwandig','Zulassung: UL 224 (außer transparent)']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"dünnwandig, flammhemmend, flexibel, UL-zugelassen, ultra-dünnwandig"},{"label":"Zulassung","value":"UL 224 (außer transparent)"},{"label":"Betriebstemperatur min.","value":"-55 °C"},{"label":"Betriebstemperatur max.","value":"125 °C"},{"label":"Durchmesser innen von (mm)","value":"0,70"},{"label":"Durchmesser innen bis (mm)","value":"61,00"},{"label":"Schrumpfrate","value":"2:1"},{"label":"Schrumpftemperatur","value":"90 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BPUTW-3.pdf','/bit/products/schrumpfschlauch-ultra-duennwandig-bputw.webp','Ultra dünnwandiger Schrumpfschlauch','published',41) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpfschlauch-uv-bestaendig-bpmw','schrumpfschlauch','BPMW','Mittelwandiger Schrumpfschlauch aus Polyolefin, UV-beständig','BPMW · Polyolefin','Der BPMW ist ein mittelwandiger Schrumpfschlauch aus Polyolefin mit hervorragenden mechanischen Eigenschaften und hohem Schrumpfverhältnis. Das Material überzeugt durch eine sehr gute UV-Beständigkeit. Der mittelwandige UV-beständige Schrumpfschlauch ist auch mit Kleberbeschichtung erhältlich: BPMW A','Polyolefin','-55 °C bis 110 °C','Meter',ARRAY['Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm','Ø 120 mm','Ø 150 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Hohes Schrumpfverhältnis','Mittelwandig','UV-beständig']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"hohes Schrumpfverhältnis, mittelwandig, UV-beständig"},{"label":"Betriebstemperatur min.","value":"-55 °C"},{"label":"Betriebstemperatur max.","value":"110 °C"},{"label":"Durchmesser innen von (mm)","value":"9,00"},{"label":"Durchmesser innen bis (mm)","value":"350,00"},{"label":"Schrumpfrate","value":"3:1"},{"label":"Schrumpftemperatur","value":"120 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BPMW-3.pdf','/bit/products/schrumpfschlauch-uv-bestaendig-bpmw.jpg','Mittelwandiger Schrumpfschlauch aus Polyolefin, UV-beständig','published',42) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('silikon-schrumpfschlauch-sk-250-flexibel-silikonschrumpfschlauch','schrumpfschlauch','SK 250','Sehr flexibler Schrumpfschlauch aus Silikon','SK 250 · VMQ (Silikon)','SK 250 Silikonschrumpfschlauch bietet eine besonders hohe Flexibilität und kann bis zu einer Temperatur von 200°C eingesetzt werden. Das Material wird im Allgemeinen für die Isolierung und Bündelung von Kabeln eingesetzt, wenn eine gute physikalische Festigkeit oder Beständigkeit gegen hohe Temperaturen erforderlich sind. Der Silikonschrumpfschlauch hält auch den meisten Sterilisationsverfahren stand und ist daher ideal für den Einsatz in medizinischen Anwendungen geeignet. Eigenschaften: Schrumpfrate: 1,5:1 Schrumpftemperatur: >80°C Hochflexibel bei extremen Temperaturen Betriebstemperatur -50°C bis +200°C Standardfarben: Grau und Schwarz','VMQ (Silikon)','-50 °C bis +200 °C','Meter',ARRAY['Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm']::text[],ARRAY['Schwarz','Grau','Andere auf Anfrage']::text[],ARRAY['Flexibel','Hohe Temperaturbeständigkeit']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"VMQ (Silikon)"},{"label":"Besonderheiten","value":"flexibel, hohe Temperaturbeständigkeit"},{"label":"Betriebstemperatur min.","value":"-50 °C"},{"label":"Betriebstemperatur max.","value":"+200 °C"},{"label":"Durchmesser innen von (mm)","value":"1,00"},{"label":"Durchmesser innen bis (mm)","value":"41,00"},{"label":"Schrumpfrate","value":"1.5:1"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/SK-250-1.pdf','/bit/products/silikon-schrumpfschlauch-sk-250-flexibel-silikonschrumpfschlauch.jpg','Sehr flexibler Schrumpfschlauch aus Silikon','published',43) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('walzenschrumpfschlauch-aus-fep-hochleistungs-rollcover','schrumpfschlauch','FEP RollCover','FEP RollCover','FEP','Ein Walzenschrumpfschlauch aus FEP bietet optimalen Schutz für Walzen in der Industrie. Durch seine herausragenden Materialeigenschaften – wie Hitzebeständigkeit, Antihaftwirkung und chemische Resistenz – eignet sich unser FEP-Rollcover ideal als Walzenbeschichtung in anspruchsvollen Produktionsumgebungen. Als Spezialist für Hochleistungskunststoffe liefert die BIT Bierther GmbH maßgeschneiderte Walzenschrumpfschläuche für verschiedenste Branchen – zuverlässig, präzise und langlebig.','FEP',NULL,'Meter',ARRAY['Standardausführung']::text[],ARRAY['Transparent']::text[],ARRAY['Antiadhäsiv','UV-beständig']::text[],ARRAY['Isolation & Aderkennzeichnung','Zugentlastung','Korrosions- & Spritzwasserschutz','Bündelung von Leitungen']::text[],'[{"label":"Werkstoff","value":"FEP"},{"label":"Besonderheiten","value":"antiadhäsiv, UV-beständig"},{"label":"Betriebstemperatur max.","value":"+205 °C"},{"label":"Schrumpftemperatur","value":"180 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2024/05/FEP-RollCover.pdf','/bit/products/walzenschrumpfschlauch-aus-fep-hochleistungs-rollcover.jpg','FEP Walzenschrumpfschlauch','published',44) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
