insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('bis-105-ul-y','isolierschlauch','BIS 105 UL-Y','Isolierschlauch aus Weich PVC mit UL-Zulassung','BIS 105 UL-Y · Weich-PVC','Der BIS 105 UL-Y ist ein flexibler, speziell formulierter Isolierschlauch aus Weich PVC für Anforderungen nach UL. Das hauptsächliche Einsatzgebiet dieser Isolierschläuche befindet sich im Bereich der Isolation und Bündelung von Litzen und Kabeln.','Weich-PVC','-40 °C bis +105 °C','Meter',ARRAY['Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm']::text[],ARRAY['Schwarz','Rot','Weiß','Blau','Gelb','Transparent','Grau','Orange']::text[],ARRAY['Sehr flexibel','Selbstverlöschend','UL-zugelassen','Zulassung: UL 224']::text[],ARRAY['Aderisolation','Schaltschrank- & Gerätebau','Trafo- & Spulenwicklung','Hochtemperaturbereiche']::text[],'[{"label":"Werkstoff","value":"Weich-PVC"},{"label":"Besonderheiten","value":"sehr flexibel, selbstverlöschend, UL-zugelassen"},{"label":"Zulassung","value":"UL 224"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"+105 °C"},{"label":"Durchmesser innen von (mm)","value":"1,0"},{"label":"Durchmesser innen bis (mm)","value":"25,0"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2023/06/BIS-105-UL-Y-5.pdf','/bit/products/bis-105-ul-y.webp','Isolierschlauch aus Weich PVC mit UL-Zulassung','published',46) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('bis-pvc-gewebeschlauch','isolierschlauch','BIS PVC GEW','BIS PVC GEW','Weich-PVC','Der dreischichtige transparente Gewebeschlauch aus Weich-PVC mit hochfester Polyester-Gewebeeinlage eignet sich hervorragend für den vielseitigen industriellen Einsatz. Durch seine flexible Struktur und gute Transparenz bietet er eine praktische Lösung für das Fördern von Flüssigkeiten, Druckluft und Chemikalien – auch im Lebensmittelbereich. PVC Material, zugelassen für Food Contact. Hohe Druckbeständigkeit auch in verschiedenen Farben erhältlich. Innen und außen glatt. Anwendungsbereiche Lebensmittel und Getränke Druckluftsysteme Chemische Substanzen Tätigkeitsbereiche Automobilindustrie Bauindustrie, Maschinenbau Lebensmittel- und Getränkeindustrie Brauereien, Molkereien Chemieindustrie, Labore Drucklufttechnik Montage- und Reparaturbetriebe, Kfz-Werkstätten Vorteile des BIS PVC Gewebeschlauchs Lebensmittelecht Flexibel und weich, einfach zu handhaben Gewebeverstärkung für erhöhten Druckwiderstand Transparent – Flüssigkeiten sind sichtbar Besonderheiten PVC Material, zugelassen für Food Contact. Hohe Druckbeständigkeit auch in verschiedenen Farben erhältlich. Innen und außen glatt. Der Gewebeschlauch aus PVC ist ideal für die Leitung von Flüssigkeiten geeignet. Vor der Nutzung sollte der Gewebeschlauch immer gereinigt werden. Darüber hinaus ist der Gewebeschlauch auch als Druckluftschlauch in der Industrie einsetzbar, insbesondere in hydraulischen Anlagen und Druckluftsystemen. Technische Daten Eigenschaft Wert Material Weich-PVC mit Polyester-Gewebe Aufbau 3-schichtig Temperaturbereich -20 °C bis +65 °C Lebensmitteleignung Ja Farbe Transparent Druckbeständigkeit Durch Gewebeeinlage erhöht FAQ – Häufig gestellte Fragen Kann ich den Schlauch für Druckluft verwenden? Ja, durch seine Gewebeverstärkung ist er für Druckluftanwendungen gut geeignet. Welche Farben sind erhältlich? Standard ist transparent, Sonderfarben sind auf Anfrage möglich. Jetzt transparenten PVC Gewebeschlauch bestellen PVC Gewebeschläuche in Industriequalität – Jetzt Angebot anfordern oder Beratung erhalten!','Weich-PVC','-20 °C bis +65 °C','Meter',ARRAY['Standardausführung']::text[],ARRAY['Transparent','Andere auf Anfrage']::text[],ARRAY['Elastisch']::text[],ARRAY['Aderisolation','Schaltschrank- & Gerätebau','Trafo- & Spulenwicklung','Hochtemperaturbereiche']::text[],'[{"label":"Werkstoff","value":"Weich-PVC"},{"label":"Besonderheiten","value":"elastisch"},{"label":"Betriebstemperatur min.","value":"-20 °C"},{"label":"Betriebstemperatur max.","value":"+65 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2022/08/BIS-PVC-GEW.pdf','/bit/products/bis-pvc-gewebeschlauch.jpg','PVC Gewebeschlauch','published',47) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('fep-schlauch-transparent-chemisch-bestaendig','isolierschlauch','FEP ISO','Ihre Vorteile bei BIT-GmbH:','FEP ISO · FEP','Unser FEP Schlauch bietet zuverlässige Eigenschaften für technische Anwendungen, bei denen höchste Anforderungen an Chemikalienresistenz und Temperaturbeständigkeit gestellt werden. Der transparente Schlauch aus Fluorethylenpropylen (FEP) eignet sich ideal für Labor, Industrie, Medizintechnik, Lebensmittelverarbeitung und viele andere Bereiche. Was ist ein FEP Schlauch? Ein FEP Schlauch besteht aus Fluorethylenpropylen – einem teilkristallinen, schmelzverarbeitbaren Fluorpolymer, das ähnlich wie PTFE (Teflon) aufgebaut ist, aber besser verformbar und transparent ist. Durch seine ausgezeichneten Materialeigenschaften wird FEP in zahlreichen High-Tech-Bereichen eingesetzt, in denen aggressive Medien transportiert oder elektrische Komponenten isoliert werden müssen. Eigenschaften & Vorteile im Überblick Hohe chemische Beständigkeit – auch gegen starke Säuren, Basen und Lösungsmittel Temperaturbereich : bis +205 °C UV- und witterungsbeständig – ideal für den Außeneinsatz Transparenz für optische Kontrolle des Mediums Sehr gute elektrische Isolationseigenschaften Physiologisch unbedenklich – geeignet für Lebensmittelkontakt und Pharmatechnik (FDA-konform) Geringe Reibung und hohe Oberflächengüte Alterungs- und diffusionsträge Anwendungsbereiche für FEP Schläuche Dank seiner vielseitigen Eigenschaften findet der FEP Schlauch in unterschiedlichsten Branchen Anwendung: Chemie- und Verfahrenstechnik: für aggressive Flüssigkeiten und Gase Labor- und Medizintechnik: sterilisierbar, beständig und transparent Lebensmittel- und Getränkeindustrie: geschmacksneutral und hygienisch Elektronik und Halbleiterindustrie: als Isolationsmaterial Automobiltechnik: für Kraftstoffe, Hydraulikflüssigkeiten und mehr FEP Schlauch individuell nach Maß anfragen Bei BIT bieten wir Ihnen FEP Schläuche in individuellen Längen, Innendurchmessern und Wandstärken . Sie können sowohl Standardgrößen als auch Sonderanfertigungen oder Zuschnitte nach Maß anfragen – ganz auf Ihre Anwendung abgestimmt. Ob für Prototypen, Kleinserien oder industrielle Großanwendungen – wir liefern Ihnen die passende Lösung. Fragen Sie Ihren FEP Schlauch direkt über unser Kontaktformular an oder senden Sie uns Ihre technischen Spezifikationen per E-Mail. Individuelle Beratung und technische Unterstützung Maßgeschneiderte Zuschnitte & Sonderabmessungen Kurze Lieferzeiten & hochwertige Qualität Langjährige Erfahrung mit Fluorpolymer-Schläuchen Jetzt FEP Schlauch bei BIT anfragen Zögern Sie nicht – kontaktieren Sie uns noch heute für ein unverbindliches Angebot. Gemeinsam finden wir die passende Lösung für Ihre technische Anwendung. → Zum Kontaktformular → Anfrage per E-Mail senden → Telefonische Beratung: +49 (0) 2254-9610-0','FEP','-67 °C bis +205 °C','Meter',ARRAY['Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm']::text[],ARRAY['Transparent']::text[],ARRAY['Hohe Biegelastwechselfähigkeit','Hohe chemische Beständigkeit','Hohe Temperaturbeständigkeit','Unbrennbar']::text[],ARRAY['Aderisolation','Schaltschrank- & Gerätebau','Trafo- & Spulenwicklung','Hochtemperaturbereiche']::text[],'[{"label":"Werkstoff","value":"FEP"},{"label":"Besonderheiten","value":"hohe Biegelastwechselfähigkeit, hohe chemische Beständigkeit, hohe Temperaturbeständigkeit, unbrennbar"},{"label":"Betriebstemperatur min.","value":"-67 °C"},{"label":"Betriebstemperatur max.","value":"+205 °C"},{"label":"Durchmesser innen von (mm)","value":"0,80"},{"label":"Durchmesser innen bis (mm)","value":"20,00"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2022/08/FEP-ISO.pdf','/bit/products/fep-schlauch-transparent-chemisch-bestaendig.jpeg','Transparenter FEP Schlauch chemikalienbeständig von BIT Bierther GmbH','published',48) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
