insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('isolierschlauch-bis-vit','isolierschlauch','BIS VIT','Viton Schlauch / Isolierschlauch aus Viton®*-Fluorelastomer','BIS VIT · FKM','Der BIS VIT ist ein Isolierschlauch aus Viton®*-Fluorelastomer. Er ist optimal zum Schutz elektronischer Bauteile in Hochtemperatursystemen geeignet und zeichnet sich durch eine sehr hohe Beständigkeit gegen Öle, Säuren und weitere Chemikalien aus. *Viton™ ist eine Handelsmarke der Chemours Company FC, LLC Viton Schlauch Der Viton Schlauch BIS VIT (auch bekannt als FKM Schlauch) ist speziell für sehr hohe Temperaturen und höchste chemische Beständigkeit entwickelt worden. Chemische Beständigkeit von Viton Schlauch Die Viton-Schläuche weisen eine bemerkenswerte Beständigkeit gegen Kohlenwasserstoffe, Mineralöle, Pflanzenöle und Pflanzenfette auf. Außerdem umfasst ihre Beständigkeit auch Witterungseinflüsse und Ozon. Vielseitiger Einsatz von Viton Schlauch Aufgrund der hervorragenden Abriebfestigkeit und Elastizität ist Viton Schlauch sehr universell einsetzbar. BIS VIT ist als Rollenware und in Abschnitten nach Kundenvorgabe erhältlich . Temperaturbeständigkeit von Viton Schlauch Das Fluorelastomer Viton zeichnet sich durch herausragende thermische Eigenschaften aus, die auch im Dauerbetrieb stabil bleiben. Die Schläuche können einem Temperaturbereich von -20 °C bis +200 °C standhalten.','FKM','-20 °C bis 200 °C','Meter',ARRAY['Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Hohe chemische Beständigkeit','Hohe Temperaturbeständigkeit','Sehr flexibel']::text[],ARRAY['Aderisolation','Schaltschrank- & Gerätebau','Trafo- & Spulenwicklung','Hochtemperaturbereiche']::text[],'[{"label":"Werkstoff","value":"FKM"},{"label":"Besonderheiten","value":"hohe chemische Beständigkeit, hohe Temperaturbeständigkeit, sehr flexibel"},{"label":"Betriebstemperatur min.","value":"-20 °C"},{"label":"Betriebstemperatur max.","value":"200 °C"},{"label":"Durchmesser innen von (mm)","value":"1.00"},{"label":"Durchmesser innen bis (mm)","value":"30.00"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BIS-VIT-1.pdf','/bit/products/isolierschlauch-bis-vit.jpg','Isolierschlauch BIS VIT','published',59) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
