insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('silikonschlauch-bis-si-ul','isolierschlauch','BIS SI UL','Silikon-Isolierschlauch mit UL-Zulassung','BIS SI UL · VMQ (Silikon)','Der BIS SI UL ist ein hochflexibler, halogenfreier Isolierschlauch aus hochwertigem Silikonkautschuk. Er ist durch seine hervorragenden chemischen und physikalischen Eigenschaften für viele Anwendungsbereiche geeignet. Prüfbericht nach UL 94 – HB','VMQ (Silikon)','-50 °C bis 200 °C','Meter',ARRAY['Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Halogenfrei','Sehr flexibel','UL-zugelassen','Zulassung: UL 224']::text[],ARRAY['Aderisolation','Schaltschrank- & Gerätebau','Trafo- & Spulenwicklung','Hochtemperaturbereiche']::text[],'[{"label":"Werkstoff","value":"VMQ (Silikon)"},{"label":"Besonderheiten","value":"halogenfrei, sehr flexibel, UL-zugelassen"},{"label":"Zulassung","value":"UL 224"},{"label":"Betriebstemperatur min.","value":"-50 °C"},{"label":"Betriebstemperatur max.","value":"200 °C"},{"label":"Durchmesser innen von (mm)","value":"0,80"},{"label":"Durchmesser innen bis (mm)","value":"18,00"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2026/03/BIS-SI-UL-3.pdf','/bit/products/silikonschlauch-bis-si-ul.jpg','Silikonschlauch UL','published',66) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('silikonschlauch-si-din-40628','isolierschlauch','BIS SI','Silikon-Isolierschlauch nach DIN 40628','BIS SI · VMQ (Silikon)','Der BIS SI ist ein sehr flexibler, halogenfreier Isolierschlauch aus Silikon, nach DIN 40628. Das Material erfüllt besonders anspruchsvolle Anforderungen in Bezug auf Temperaturbeständigkeit, Flexibilität und Beständigkeit gegenüber Chemikalien. Der Silikonschlauch nach DIN 40628 wird in Ringen geliefert und ist in der Standardfarbe „naturfarben“ erhältlich. Für individuelle Anforderungen können andere Farben, Shore-Härten, Wandstärken und Längen auf Anfrage angepasst werden.','VMQ (Silikon)','-60 °C bis 200 °C','Meter',ARRAY['Ø 0,5 mm','Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm','Ø 120 mm','Ø 150 mm']::text[],ARRAY['Transparent','Andere auf Anfrage']::text[],ARRAY['Halogenfrei','Hohe Temperaturbeständigkeit','Sehr flexibel']::text[],ARRAY['Aderisolation','Schaltschrank- & Gerätebau','Trafo- & Spulenwicklung','Hochtemperaturbereiche']::text[],'[{"label":"Werkstoff","value":"VMQ (Silikon)"},{"label":"Besonderheiten","value":"halogenfrei, hohe Temperaturbeständigkeit, sehr flexibel"},{"label":"Betriebstemperatur min.","value":"-60 °C"},{"label":"Betriebstemperatur max.","value":"200 °C"},{"label":"Durchmesser innen von (mm)","value":"0,30"},{"label":"Durchmesser innen bis (mm)","value":"200,00"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BIS-SI-3.pdf','/bit/products/silikonschlauch-si-din-40628.jpg','Silikon-Isolierschlauch nach DIN 40628','published',67) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
