insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('glasgewebeschlauch-bis-155-d','glasseidenschlauch','BIS 155 (D)','Glasgewebeschlauch beschichtet mit Polyurethan-Lack','BIS 155 (D) · Glasgewebe mit Polyurethan-Beschichtung','Der BIS 155 (D) ist ein temperaturbeständiger Glasgewebeschlauch mit einer Beschichtung aus Polyurethan-Lack. Hauptsächliche Einsatzgebiete des Glasgewebeschlauches BIS 155 (D) sind die Isolierung, Bündelung und der Schutz von Litzen und Kabeln im Bereich der Motoren-, Transformatoren- und Spulenherstellung.','Glasgewebe mit Polyurethan-Beschichtung','-20 °C bis 155 °C','Meter',ARRAY['Ø 0,5 mm','Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm']::text[],ARRAY['Schwarz','Natur','Andere auf Anfrage']::text[],ARRAY['Flexibel']::text[],ARRAY['Motoren- & Transformatorenbau','Heizgeräte','Beleuchtungstechnik','Wickeltechnik']::text[],'[{"label":"Werkstoff","value":"Glasgewebe mit Polyurethan-Beschichtung"},{"label":"Besonderheiten","value":"flexibel"},{"label":"Betriebstemperatur min.","value":"-20 °C"},{"label":"Betriebstemperatur max.","value":"155 °C"},{"label":"Durchmesser innen von (mm)","value":"0,50"},{"label":"Durchmesser innen bis (mm)","value":"12,00"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BIS-155-D-1.pdf','/bit/products/glasgewebeschlauch-bis-155-d.jpg','Glasgewebeschlauch','published',69) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path