insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('glasgewebeschlauch-bis-exp-230','glasseidenschlauch','BIS EXP 230','Dehnbarer Glasgewebeschlauch mit Silikonbeschichtung','BIS EXP 230 · Glasgewebe mit Silikon Beschichtung','Der BIS EXP-230 ist ein dehnbarer, hochflexibler Glasgewebeschlauch mit Silikonbeschichtung. Er wird einfach aufgezogen und passt sich perfekt dem zu schützenden Objekt an. Der Schlauch lässt sich bis auf das Doppelte seines Anlieferungsdurchmessers aufweiten.','Glasgewebe mit Silikon Beschichtung','-70 °C bis 235 °C','Meter',ARRAY['Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm']::text[],ARRAY['Schwarz','Weiß']::text[],ARRAY['Dehnbar','Sehr flexibel','Selbstverlöschend','UL-zugelassen','Zulassung: UL 1441']::text[],ARRAY['Motoren- & Transformatorenbau','Heizgeräte','Beleuchtungstechnik','Wickeltechnik']::text[],'[{"label":"Werkstoff","value":"Glasgewebe mit Silikon Beschichtung"},{"label":"Besonderheiten","value":"dehnbar, sehr flexibel, selbstverlöschend, UL-zugelassen"},{"label":"Zulassung","value":"UL 1441"},{"label":"Betriebstemperatur min.","value":"-70 °C"},{"label":"Betriebstemperatur max.","value":"235 °C"},{"label":"Durchmesser innen von (mm)","value":"2,00"},{"label":"Durchmesser innen bis (mm)","value":"25,00"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BIS-EXP-230.pdf','/bit/products/glasgewebeschlauch-bis-exp-230.jpg','Dehnbarer Glasgewebeschlauch mit Silikonbeschichtung','published',70) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applic