insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('glasseidenschlauch-bis-230-b','glasseidenschlauch','BIS 230 (B)','Glasseidenschlauch mit Silikonbeschichtung','BIS 230 (B) · Glasgewebe mit Silikon Beschichtung','Der BIS 230 (B) ist ein hoch temperaturbeständiger Isolierschlauch aus Glasseidengeflecht mit einer Beschichtung aus Silikonkautschuk. Das Material verfügt über eine sehr glatte und gleichmäßige Oberfläche und eignet sich für eine einfache Verarbeitung.','Glasgewebe mit Silikon Beschichtung','-40 °C bis 180 °C','Meter',ARRAY['Ø 0,5 mm','Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm']::text[],ARRAY['Schwarz','Weiß','Andere auf Anfrage']::text[],ARRAY['Hohe Temperaturbeständigkeit','Sehr flexibel','Selbstverlöschend']::text[],ARRAY['Motoren- & Transformatorenbau','Heizgeräte','Beleuchtungstechnik','Wickeltechnik']::text[],'[{"label":"Werkstoff","value":"Glasgewebe mit Silikon Beschichtung"},{"label":"Besonderheiten","value":"hohe Temperaturbeständigkeit, sehr flexibel, selbstverlöschend"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"180 °C"},{"label":"Durchmesser innen von (mm)","value":"0.50"},{"label":"Durchmesser innen bis (mm)","value":"33.00"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BIS-230-B.pdf','/bit/products/glasseidenschlauch-bis-230-b.jpg','Glasseidenschlauch mit Silikonbeschichtung','published',72) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.appli