insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('glasseidenschlauch-bis-230-d-mit-silikonbeschichtung','glasseidenschlauch','BIS 230 (D)','Glasseidenschlauch mit Silikonbeschichtung','BIS 230 (D) · Glasgewebe mit Silikon Beschichtung','Der BIS 230 (D) ist ein hoch temperaturbeständiger und flexibler Glasseidenschlauch mit Silikonbeschichtung. Aufgrund der sehr guten chemischen, mechanischen und elektrischen Eigenschaften bietet er eine perfekte elektrische Isolation und Schutz vor mechanischer Beanspruchung. Er eignet sich hervorragend zur Isolierung von Anschlusselementen im Bereich von Motoren, Transformatoren und zur Spulenherstellung.','Glasgewebe mit Silikon Beschichtung','-60 °C bis 220 °C','Meter',ARRAY['Ø 0,5 mm','Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm']::text[],ARRAY['Schwarz','Weiß','Andere auf Anfrage']::text[],ARRAY['Hohe Temperaturbeständigkeit','Sehr flexibel']::text[],ARRAY['Motoren- & Transformatorenbau','Heizgeräte','Beleuchtungstechnik','Wickeltechnik']::text[],'[{"label":"Werkstoff","value":"Glasgewebe mit Silikon Beschichtung"},{"label":"Besonderheiten","value":"hohe Temperaturbeständigkeit, sehr flexibel"},{"label":"Betriebstemperatur min.","value":"-60 °C"},{"label":"Betriebstemperatur max.","value":"220 °C"},{"label":"Durchmesser innen von (mm)","value":"0,50"},{"label":"Durchmesser innen bis (mm)","value":"20,00"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BIS-230-D-2.pdf','/bit/products/glasseidenschlauch-bis-230-d-mit-silikonbeschichtung.jpg','Glasseidenschlauch mit Silikonbeschichtung','published',73) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
