insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('aramid-geflechtschlauch','geflechtschlauch','BIS GE ARAMID','ARAMID Geflechtschlauch','BIS GE ARAMID','Sehr flexibler, dehnbarer Geflechtschlauch aus Aramidfasern. Der BIS GE ARAMID bietet eine hervorragende Temperaturbeständigkeit, Zugfestigkeit und Abriebfestigkeit zum Schutz empfindlicher Kabel, Leitungen und Drähte.','—','-70 °C bis +180 °C','Meter',ARRAY['Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm','Ø 120 mm','Ø 150 mm']::text[],ARRAY['Gelb']::text[],ARRAY['Dehnbar','Flammhemmend','Flexibel','Hohe Temperaturbeständigkeit','Selbstverlöschend']::text[],ARRAY['Kabelbündelung','Scheuer- & Abriebschutz','Maschinen- & Anlagenbau','Fahrzeug- & Motorraum']::text[],'[{"label":"Besonderheiten","value":"dehnbar, flammhemmend, flexibel, hohe Temperaturbeständigkeit, selbstverlöschend"},{"label":"Betriebstemperatur min.","value":"-70 °C"},{"label":"Betriebstemperatur max.","value":"+180 °C"},{"label":"Durchmesser innen von (mm)","value":"2,0"},{"label":"Durchmesser innen bis (mm)","value":"150,0"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2023/04/BIS-GE-ARAMID.pdf','/bit/products/aramid-geflechtschlauch.jpg','Aramid-Geflechtschlauch für industriellen Kabelschutz und Hitzebeständigkeit','published',75) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt