insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('bis-ge-carbon-geflechtschlauch','geflechtschlauch','BIS GE CARBON','Vorteile des BIS GE CARBON Geflechtschlauchs','BIS GE CARBON · Carbonfaser','Der BIS GE CARBON Geflechtschlauch aus hochwertigen Carbonfaser-Garnen bietet außergewöhnliche Festigkeit, hohe Temperaturbeständigkeit und extreme Leichtbauweise. Dieses Hochleistungsprodukt passt sich flexibel unregelmäßigen oder asymmetrischen Oberflächen an und bietet gleichzeitig volle radiale Stabilität und Torsionsfestigkeit. Die hervorragenden Eigenschaften machen diesen Schlauch zu einem unverzichtbaren Bauteil in modernen Hochtechnologie-Anwendungen . Außergewöhnliche Temperaturbeständigkeit : Funktioniert bei extrem niedrigen (bis -269℃) und hohen Temperaturen (bis +650℃) Hohe Festigkeit bei extrem geringem Gewicht : Bietet exzellenten mechanischen Schutz ohne das Gesamtgewicht zu erhöhen Vielseitig einsetzbar : Passt sich unregelmäßigen Oberflächen an und bietet gleichzeitig ausgezeichnete Stabilität Flammenresistenz : Flammhemmende Eigenschaft (VW-1) Material : BIS GE CARBON (Carbonfaser) Betriebstemperatur : -269℃ bis +650℃ Flammwidrigkeit : VW-1 Schneidwerkzeug : Schere Leitfähigkeit : Leitfähig Zulassungen : RoHS-konform Der BIS GE CARBON Geflechtschlauch bietet eine langlebige und robuste Schutzschicht für Kabel, Drahtbündel, Kabelbäume, Rohre und Schläuche in luft- und raumfahrttechnischen , militärischen sowie anderen high-tech Industrien. Insbesondere in Bereichen, in denen extreme Temperaturen , mechanische Belastungen und Anforderungen an ein geringes Gewicht bestehen, spielt dieser Schlauch eine wichtige Rolle. Typische Anwendungen umfassen: Luft- und Raumfahrt : Schutz von Kabeln und Leitungen in extremen Klimazonen und unter mechanischen Belastungen. Militärtechnik : Einsatz in militärischen Fahrzeugen und Ausrüstungen, die hohe Ansprüche an Schutz und Widerstandsfähigkeit stellen. Automotive und Hochleistungsfahrzeuge : Kabelschutz in Hochleistungsfahrzeugen, insbesondere bei Rennsportanwendungen. Elektroinstallation und Energieverteilung : Schutz für Kabel und Leitungen in Bereichen mit hohem Risiko von Hitzeschäden und Abrieb.','Carbonfaser','-269 °C bis +650 °C','Meter',ARRAY['Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Hohe Temperaturbeständigkeit']::text[],ARRAY['Kabelbündelung','Scheuer- & Abriebschutz','Maschinen- & Anlagenbau','Fahrzeug- & Motorraum']::text[],'[{"label":"Werkstoff","value":"Carbonfaser"},{"label":"Besonderheiten","value":"hohe Temperaturbeständigkeit"},{"label":"Betriebstemperatur min.","value":"-269 °C"},{"label":"Betriebstemperatur max.","value":"+650 °C"},{"label":"Durchmesser innen von (mm)","value":"1"},{"label":"Durchmesser innen bis (mm)","value":"65"}]'::jsonb,NULL,'/bit/products/bis-ge-carbon-geflechtschlauch.png','Carbon Geflechtschlauch braided sleeve','published',76) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('bis-ge-pa-cu-emv-abschirmgeflecht','geflechtschlauch','BIS GE PA/CU EMV','Abschirmgeflecht BIS GE PA/CU EMV Geflechtschlauch aus Polyamid 6.6 mit verzinntem Kupfer','BIS GE PA/CU EMV · PA 6.6','Abschirmgeflecht BIS GE PA/CU EMV Materialzusammensetzung: Polyamid 6.6-Fäden, einzeln umwickelt mit verzinntem Kupfer. Fadenstärke Inlay PA 6.6: 0,25mm Fadenstärke gesamt: 0,27 mm Eigenschaften und Vorteile: Leicht dehnbar und montierbar durch den PA-Innenkern, Zeitersparnis im Vergleich zu Vollmaterial Keine Verletzungsgefahr während der Montage im Vergleich zu Vollmaterial Gute mechanische Abriebfestigkeit Gute Korrosionsbeständigkeit durch verzinntes Kupfer Gewichtsersparnis im Vergleich zum Kupfer-Vollmaterial verbesserte Schirmwerte bei niedrigeren Frequenzen im Vergleich zum BIS GE PA/EMV Verarbeitung und Montage: Minimales Ausfransen beim Schneiden mit scharfem Werkzeug Nach dem Schneiden und Montage gegen Ausfransen schützen (z. B. Schrumpfschlauch) Wichtig: Erdung nicht vergessen Kunden müssen anwendungsbezogene Tests für Input, Output, Einbausituation, Erdung usw. durchführen Anwendungsbereich: Geeignet als Abschirmgeflecht auch für moderne E-Autos, Roboter, Steuerungen','PA 6.6','-40 °C bis +180 °C','Meter',ARRAY['Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm']::text[],ARRAY['Grau','Andere auf Anfrage']::text[],ARRAY['Dehnbar','Elastisch','Flexibel','Gewebe']::text[],ARRAY['Kabelbündelung','Scheuer- & Abriebschutz','Maschinen- & Anlagenbau','Fahrzeug- & Motorraum']::text[],'[{"label":"Werkstoff","value":"PA 6.6"},{"label":"Besonderheiten","value":"dehnbar, elastisch, flexibel, Gewebe"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"+180 °C"},{"label":"Durchmesser innen von (mm)","value":"4,0"},{"label":"Durchmesser innen bis (mm)","value":"16,0"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2023/12/BIS-GE-PA_CU-EMV-1.pdf','/bit/products/bis-ge-pa-cu-emv-abschirmgeflecht.jpg','Abschirmgeflecht','published',77) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('emv-geflechtschlauch-bis-ge-pa-emv','geflechtschlauch','BIS GE PA/EMV','EMV Geflechtschlauch aus PA 6.6 mit Silber-Beschichtung','BIS GE PA/EMV · PA 6.6','Der BIS GE PA / EMV ist ein hochflexibler EMV Geflechtschlauch aus Polyamid 6.6, der ideal zur Abschirmung von hochfrequenter Strahlung eingesetzt werden kann. Durch die Beschichtung mit reinem Silber werden Abschirmwerte bis zu 54dB erreicht.','PA 6.6','-40 °C bis 160 °C','Meter',ARRAY['Ø 1 mm','Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm']::text[],ARRAY['Grau']::text[],ARRAY['Halogenfrei','Hohe Temperaturbeständigkeit']::text[],ARRAY['Kabelbündelung','Scheuer- & Abriebschutz','Maschinen- & Anlagenbau','Fahrzeug- & Motorraum']::text[],'[{"label":"Werkstoff","value":"PA 6.6"},{"label":"Besonderheiten","value":"halogenfrei, hohe Temperaturbeständigkeit"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"160 °C"},{"label":"Durchmesser innen von (mm)","value":"1.00"},{"label":"Durchmesser innen bis (mm)","value":"115.00"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BIS-GE-PA-EMV.pdf','/bit/products/emv-geflechtschlauch-bis-ge-pa-emv.jpg','EMV-Geflechtschlauch BIS GE PA/EMV','published',78) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,im