insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('geflechtschlauch-pa-polyamid','geflechtschlauch','BIS GE PA','BIS GE PA','PA 6.6','Der Geflechtschlauch aus Polyamid 6.6 von BIT ist die optimale Lösung zur Kabelbündelung in anspruchsvollen Anwendungen. Die robuste Flechtstruktur mit dicken Monofilfäden sorgt für hervorragende Abriebfestigkeit , während die hohe Expansionsrate von 2:1 eine einfache Montage auch über Stecker oder unregelmäßige Formen erlaubt. Ihre Vorteile im Überblick Hohe Flexibilität durch 2:1-Expansionsrate Abriebfest durch dicke PA-Fasern Halogenfrei, selbstverlöschend, RoHS- und WEEE-konform Temperaturbereich: -40°C bis +180°C Schmelztemperatur: +245°C Fadenstärke: 0,27 mm ± 0,03 mm Farben: Standard Schwarz und Grau, Sonderfarben auf Anfrage Verfügbare Ausführungen & Individualisierung Unser Geflechtschlauch ist in Standarddurchmessern von 1,5 mm bis 120 mm erhältlich. Auch Sonderanfertigungen mit individuellen Aufweitraten oder Farben sind bei uns möglich – bereits bei geringen Mindestmengen. Lieferformen Auf Spulen (endlos) In Ringen Thermisch abgelängt nach Kundenvorgabe – kein Ausfransen Anwendungsbereiche Industrie- und Maschinenbau Automobiltechnik Elektrotechnik und Schaltschrankbau Robuste Verkabelung in rauer Umgebung Technische Daten im Überblick Eigenschaft Wert Material Polyamid 6.6 (PA) Expansionsrate 2:1 Temperaturbereich -40°C bis +180°C Schmelztemperatur +245°C Fadenstärke 0,27 mm ± 0,03 mm Flammverhalten Selbstverlöschend, Nachbrenndauer 0 Sekunden Konformität RoHS, WEEE FAQ – Häufig gestellte Fragen zum Geflechtschlauch Wofür wird ein Geflechtschlauch verwendet? Geflechtschläuche dienen dem Schutz und der Bündelung von Kabeln. Sie schützen vor Abrieb, mechanischer Beanspruchung und erleichtern die Organisation von Kabelbäumen. Ist der Geflechtschlauch temperaturbeständig? Ja, der PA-Geflechtschlauch ist für einen Temperaturbereich von -40 °C bis +180 °C geeignet. Welche Längen sind verfügbar? Wir liefern Geflechtschlauch in Spulen, Ringen oder auf Wunsch thermisch abgelängt. Kann ich Sonderfarben oder Kennfäden bestellen? Ja, auf Anfrage liefern wir auch farbige Varianten oder Ausführungen mit Kennfäden für die einfache Identifikation. Ist der Geflechtschlauch RoHS-konform? Ja, unsere Produkte entsprechen den aktuellen RoHS- und WEEE-Richtlinien. Jetzt Geflechtschlauch direkt bestellen Kontaktieren Sie uns für ein individuelles Angebot oder bei Fragen zu Spezifikationen, Sonderanfertigungen oder Lieferzeiten. Die BIT Bierther GmbH ist Ihr zuverlässiger Partner für Kabelschutzsysteme und Geflechtschläuche in Industriequalität . UL 94 Prüfberichte: Prüfbericht nach UL 94 – HB Prüfbericht nach UL 94 – V0','PA 6.6','-40 °C bis 180 °C','Meter',ARRAY['Ø 1,5 mm','Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm']::text[],ARRAY['Schwarz','Rot','Blau','Gelb','Grün','Grau','Orange','Andere auf Anfrage']::text[],ARRAY['Halogenfrei','Hohe Temperaturbeständigkeit','Selbstverlöschend']::text[],ARRAY['Kabelbündelung','Scheuer- & Abriebschutz','Maschinen- & Anlagenbau','Fahrzeug- & Motorraum']::text[],'[{"label":"Werkstoff","value":"PA 6.6"},{"label":"Besonderheiten","value":"halogenfrei, hohe Temperaturbeständigkeit, selbstverlöschend"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"180 °C"},{"label":"Durchmesser innen von (mm)","value":"1,50"},{"label":"Durchmesser innen bis (mm)","value":"115,00"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BIS-GE-PA-1.pdf','/bit/products/geflechtschlauch-pa-polyamid.jpg','Geflechtschlauch BIS GE PA','published',81) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('geflechtschlauch-selbstschliessend-wrap-pet','geflechtschlauch','BIS WRAP PET','BIS WRAP PET','PET','Unser selbstschließender Geflechtschlauch BIS WRAP PET ist die ideale Lösung für das Bündeln und Schützen von Kabeln und Leitungen . Dank seiner speziellen Struktur lässt sich der Schlauch ganz einfach öffnen und wieder verschließen – perfekt für Anwendungen, bei denen Kabel regelmäßig nachgerüstet oder ausgetauscht werden müssen. Vielseitiger Kabelschutz für Industrie und Technik Der Geflechtschlauch aus PET überzeugt durch seine hohe Flexibilität, Abriebfestigkeit und Temperaturbeständigkeit. Er eignet sich hervorragend für anspruchsvolle Einsatzbereiche wie Automobilindustrie, Maschinenbau, Elektrotechnik sowie für den privaten Gebrauch im Heim- und Bürobereich. Eigenschaften des BIS WRAP PET Geflechtschlauchs Selbstschließende Struktur – kein Werkzeug erforderlich Flexibel, wiederverwendbar und einfach zu montieren Hervorragende Abriebfestigkeit Temperaturbeständig von -50 °C bis +150 °C Gute Belüftung durch offene Struktur Geringes Gewicht und platzsparendes Design Typische Anwendungsbereiche Kabelbündelung in Schaltschränken und Rechenzentren Nachrüstung und Schutz von Kabeln im KFZ-Bereich Leitungsmanagement im Maschinen- und Anlagenbau Kabelorganisation im Home-Office oder bei Multimedia-Systemen Jetzt BIS WRAP PET Geflechtschlauch anfragen Entdecken Sie die einfache und professionelle Lösung für Ihr Kabelmanagement mit dem BIS WRAP PET Geflechtschlauch von BIT . Jetzt anfragen und von unserer qualitätsgeprüften Auswahl profitieren.','PET','-55 °C bis 150 °C','Meter',ARRAY['Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Für nachträgliche Montage