insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('edelstahlkabelbinder-gtme-kabelbinder-aus-edelstahl','kabelbinder','GTME','GTME','Edelstahl AISI 304 und AISI 316','Unsere GTME Edelstahlkabelbinder sind die ideale Lösung, wenn mechanische Belastbarkeit, hohe Temperaturbeständigkeit und langfristige Sicherheit gefragt sind. Ob in industriellen Anlagen, im Tunnelbau, bei der Bahn oder im Außenbereich – mit einem Kabelbinder aus Edelstahl sichern Sie Leitungen, Schläuche oder Bauteile zuverlässig. Eigenschaften der GTME Edelstahl-Kabelbinder ✔ Material: rostfreier Edelstahl AISI 304 oder AISI 316 ✔ Temperaturbeständig von -80 °C bis +538 °C ✔ Selbstverriegelnder Kugelverschluss für schnellen Einbau ✔ UV-, witterungs- und chemikalienbeständig ✔ Erhältlich in Längen von 100 mm bis 1000 mm ✔ Breiten: 4,6 mm, 7,9 mm u. a. ✔ Optional mit Beschichtung (z. B. Polyester) für erhöhten Schutz Typische Einsatzbereiche Edelstahlkabelbinder kommen überall dort zum Einsatz, wo herkömmliche Kunststoffbinder versagen: ✔ Industrie- und Schaltanlagenbau ✔ Bahntechnik und Verkehrsinfrastruktur ✔ Schiffbau und Offshore ✔ Maschinenbau und Fördertechnik ✔ Außenbereiche mit UV- oder Hitzeeinfluss Jetzt Edelstahlkabelbinder GTME anfragen Wir beraten Sie zu Ausführungen, Verpackungseinheiten und individuellen Anforderungen. Auch bedruckte oder beschichtete Varianten sind erhältlich. ✔ Klein- und Großmengen verfügbar ✔ Technische Beratung & Expresslieferung ✔ Für Industrie, Bahn, Energie & Bau Jetzt Kontakt aufnehmen und Angebot anfordern','Edelstahl AISI 304 und AISI 316','-80 °C bis +500 °C','Stück',ARRAY['100 mm','140 mm','160 mm','200 mm','250 mm','300 mm','360 mm','370 mm','430 mm','450 mm','530 mm','600 mm','710 mm','760 mm','800 mm','1000 mm']::text[],ARRAY['Andere auf Anfrage']::text[],ARRAY['Edelstahlkabelbinder','Hohe chemische Beständigkeit','Hohe Temperaturbeständigkeit']::text[],ARRAY['Kabelbündelung','Montage & Befestigung','Außen- & UV-Einsatz','Schaltschrankbau']::text[],'[{"label":"Werkstoff","value":"Edelstahl AISI 304 und AISI 316"},{"label":"Besonderheiten","value":"Edelstahlkabelbinder, hohe chemische Beständigkeit, hohe Temperaturbeständigkeit"},{"label":"Betriebstemperatur min.","value":"-80 °C"},{"label":"Betriebstemperatur max.","value":"+500 °C"},{"label":"Länge von","value":"100 mm"},{"label":"Länge bis","value":"1000 mm"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/GTME.pdf','/bit/products/edelstahlkabelbinder-gtme-kabelbinder-aus-edelstahl.jpg','GTME','published',94) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
