insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('gt-ht-hitzebestaendige-kabelbinder','kabelbinder','GT HT','Hitzebeständige Kabelbinder','GT HT · PA 6.6','Die Kabelbinder der Serie GT HT wurden speziell für den Einsatz unter extremen Temperaturbedingungen entwickelt. Dank eines innovativen Hochleistungswerkstoffs behalten sie auch bei hohen Temperaturen ihre mechanische Festigkeit, Duktilität und Verarbeitbarkeit – ohne Kompromisse bei der Funktionalität. Das macht sie zur idealen Lösung für anspruchsvolle Anwendungen, etwa als zuverlässige Befestigungselemente im Automobilbau, wo Temperaturbeständigkeit und Belastbarkeit entscheidend sind.','PA 6.6','-40 °C bis +150 °C','Stück',ARRAY['140 mm','160 mm','200 mm','250 mm','300 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Halogenfrei','Hitzebeständig','Universell einsetzbar','Zulassung: UL 94 V2']::text[],ARRAY['Kabelbündelung','Montage & Befestigung','Außen- & UV-Einsatz','Schaltschrankbau']::text[],'[{"label":"Werkstoff","value":"PA 6.6"},{"label":"Besonderheiten","value":"halogenfrei, hitzebeständig, universell einsetzbar"},{"label":"Zulassung","value":"UL 94 V2"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"+150 °C"},{"label":"Länge von","value":"140 mm"},{"label":"Länge bis","value":"300 mm"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2025/06/GT-HT-3.pdf','/bit/products/gt-ht-hitzebestaendige-kabelbinder.jpg','hoch temperaturbeständige Kabelbinder','published',96) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.application