insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('kabelbinder-gt-mz-mit-metallzunge','kabelbinder','GT MZ','Kabelbinder mit Metallzunge','GT MZ · PA 6.6','Die Metallzunge in diesen Kabelbindern bietet eine höhere Zugfestigkeit im Vergleich zu reinen Kunststoff-Kabelbindern. Dadurch können sie größeren Belastungen standhalten und schwerere Gegenstände sicher befestigen.','PA 6.6','-40 °C bis +85 °C','Stück',ARRAY['100 mm','140 mm','160 mm','200 mm','250 mm','300 mm','360 mm']::text[],ARRAY['Schwarz','Natur']::text[],ARRAY['Mit Metallzunge','Universell einsetzbar']::text[],ARRAY['Kabelbündelung','Montage & Befestigung','Außen- & UV-Einsatz','Schaltschrankbau']::text[],'[{"label":"Werkstoff","value":"PA 6.6"},{"label":"Besonderheiten","value":"mit Metallzunge, universell einsetzbar"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"+85 °C"},{"label":"Länge von","value":"98 mm"},{"label":"Länge bis","value":"360 mm"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/GT-MZ.pdf','/bit/products/kabelbinder-gt-mz-mit-metallzunge.jpg','Kabelbinder mit Metallzunge','published',97) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('kabelbinder-gt-pp','kabelbinder','GT PP','Säurebeständige Kabelbinder aus PP ( Polypropylen )','GT PP · PP','GT PP – Kabelbinder aus Polypropylen mit geringer Wasseraufnahme und hoher Beständigkeit gegenüber Säuren und anderen Chemikalien. Säurebeständige Kabelbinder aus PP: Die perfekte Lösung für den Einsatz in aggressiven Umgebungen Säurebeständige Kabelbinder sind eine wichtige Lösung für den Einsatz in Umgebungen, in denen die Gefahr besteht, dass Kabel mit Säuren, Laugen, organischen Lösungsmitteln oder Fetten in Kontakt kommen. Sie sind aus hochwertigem Polypropylen gefertigt, das eine sehr gute Beständigkeit gegen diese aggressiven Chemikalien aufweist. Eigenschaften und Vorteile von säurebeständigen Kabelbindern Die GT PP Kabelbinder bieten eine Reihe von Vorteilen gegenüber herkömmlichen Kabelbindern: Langlebigkeit: Säurebeständiges Polypropylen ist ein robustes Material, das auch unter schwierigen Bedingungen seine Form und Festigkeit behält. Chemikalienbeständigkeit: Säurebeständige Kabelbinder sind gegenüber einer Vielzahl von Chemikalien beständig, darunter Säuren, Laugen, organische Lösungsmittel und Fette. Kabelbinder aus PP haben die Eigenschaft, auf Wasser zu treiben. Temperaturbeständigkeit: Säurebeständige Kabelbinder sind für den Einsatz bei Temperaturen zwischen -20° und 75° C geeignet. Anwendungen von säurebeständigen Kabelbindern Säurebeständige Kabelbinder aus PP werden überwiegend in der chemischen Industrie und in der Automobilindustrie zur Befestigung und Bündelung von Kabeln und Leitungen eingesetzt, die mit Kraftstoffen, Ölen und anderen aggressiven Chemikalien in Kontakt kommen können.','PP','-35 °C bis +85 °C','Stück',ARRAY['100 mm','140 mm','160 mm','200 mm','250 mm','300 mm','360 mm','370 mm']::text[],ARRAY['Grün']::text[],ARRAY['Hohe chemische Beständigkeit']::text[],ARRAY['Kabelbündelung','Montage & Befestigung','Außen- & UV-Einsatz','Schaltschrankbau']::text[],'[{"label":"Werkstoff","value":"PP"},{"label":"Besonderheiten","value":"hohe chemische Beständigkeit"},{"label":"Betriebstemperatur min.","value":"-35 °C"},{"label":"Betriebstemperatur max.","value":"+85 °C"},{"label":"Länge von","value":"100 mm"},{"label":"Länge bis","value":"370 mm"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/GT-PP.pdf','/bit/products/kabelbinder-gt-pp.jpg','Säurebeständige Kabelbinder aus PP ( Polypropylen )','published',98) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('kabelbinder-gt-soft','kabelbinder','GT Soft','Softkabelbinder','GT Soft · TPU','Der GT Soft ist ein sehr elastischer, wiederlösbarer Binder aus thermoplastischem Polyurethan. Er eignet sich hervorragend zur Bündelung von empfindlichen Kabeln und Leitungen. Der GT Soft ist mit Einfachverschluss oder Doppelkopfverschluss lieferbar.','TPU','-40 °C bis +85 °C','Stück',ARRAY['200 mm','250 mm','300 mm','360 mm','370 mm','430 mm','450 mm','530 mm','600 mm','710 mm','760 mm','800 mm']::text[],ARRAY['Schwarz','Grün']::text[],ARRAY['Sehr flexibel','Wiederlösbar']::text[],ARRAY['Kabelbündelung','Montage & Befestigung','Außen- & UV-Einsatz','Schaltschrankbau']::text[],'[{"label":"Werkstoff","value":"TPU"},{"label":"Besonderheiten","value":"sehr flexibel, wiederlösbar"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"+85 °C"},{"label":"Länge von","value":"180 mm"},{"label":"Länge bis","value":"880 mm"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/GT-Soft.pdf','/bit/products/kabelbinder-gt-soft.jpg','Soft Kabelbinder flexibel','published',99) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('kabelbinder-gtk','kabelbinder','GTK','Markierungsbinder mit Beschriftungsfeld','GTK · PA 6.6','GTK Markierungsbinder eignen sich hervorragend für die dauerhafte Kennzeichnung von Kabelbäumen.','PA 6.6','-40 °C bis +85 °C','Stück',ARRAY['100 mm','140 mm','160 mm','200 mm']::text[],ARRAY['Natur']::text[],ARRAY['Mit Beschriftungsfeld']::text[],ARRAY['Kabelbündelung','Montage & Befestigung','Außen- & UV-Einsatz','Schaltschrankbau']::text[],'[{"label":"Werkstoff","value":"PA 6.6"},{"label":"Besonderheiten","value":"mit Beschriftungsfeld"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"+85 °C"},{"label":"Länge von","value":"98 mm"},{"label":"Länge bis","value":"210 mm"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/GTK.pdf','/bit/products/kabelbinder-gtk.jpg','Markierungsbinder mit Beschriftungsfeld','published',100) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
