insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('kabelbinder-uv-bestaendig','kabelbinder','GT UV','Sind diese Kabelbinder wirklich UV-beständig?','GT UV · PA 6.6W','Unsere UV-beständigen Kabelbinder der Serie GT UV sind speziell für den Einsatz im Außenbereich entwickelt. Sie bestehen aus hochwertigem Nylon 66 mit spezieller UV-Stabilisierung und bieten zuverlässigen Halt auch bei direkter Sonneneinstrahlung. Ideal für Anwendungen in der Photovoltaik , im Gartenbau oder bei Kabelinstallationen im Freien . Vorteile der GT UV Kabelbinder ✅ UV-beständig ✅ Ideal für Außeneinsätze mit starker Sonneneinstrahlung ✅ Temperaturbeständig von -40 °C bis +85 °C ✅ Schwarze Kabelbinder mit hoher Stabilität ✅ Aus Polyamid (Nylon 66) , halogenfrei ✅ Witterungsbeständig und langlebig Anwendungsbereiche Die GT UV Kabelbinder eignen sich besonders für: Photovoltaik- und Solaranlagen Elektroinstallationen im Außenbereich Garten- und Landschaftsbau Landwirtschaftliche Technik Industrieanlagen im Außenbereich Verfügbare Größen Unsere Kabelbinder UV sind in verschiedenen Längen von 100 mm bis 708 mm erhältlich – alle mit hoher Zugfestigkeit für zuverlässige Befestigungen. FAQ – Häufige Fragen zu Kabelbinder GT UV Ja, unsere GT UV Kabelbinder bestehen aus speziell stabilisiertem Nylon 66.','PA 6.6W','-40 °C bis +85 °C','Stück',ARRAY['100 mm','140 mm','160 mm','200 mm','250 mm','300 mm','360 mm','370 mm','430 mm','450 mm','530 mm','600 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Universell einsetzbar','UV-beständig','Zulassung: ISO 4892-2, UL 62275']::text[],ARRAY['Kabelbündelung','Montage & Befestigung','Außen- & UV-Einsatz','Schaltschrankbau']::text[],'[{"label":"Werkstoff","value":"PA 6.6W"},{"label":"Besonderheiten","value":"universell einsetzbar, UV-beständig"},{"label":"Zulassung","value":"ISO 4892-2, UL 62275"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"+85 °C"},{"label":"Länge von","value":"100 mm"},{"label":"Länge bis","value":"708 mm"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2022/11/GT-UV.pdf','/bit/products/kabelbinder-uv-bestaendig.jpg','Kabelbinder UV-beständig BIT Bierther GmbH','published',109) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
