insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('durchlauf-schrumpfgeraet','verarbeitungsgeraete','Durchlauf-Schrumpfgerät','Ihre Vorteile auf einen Blick:','Durchlauf-Schrumpfgerät','Durchlauf-Schrumpfgerät – Effizienz trifft Langlebigkeit Steigern Sie Ihre Produktionsleistung mit unserem leistungsstarken elektrisch beheizten Durchlauf-Schrumpfgerät – dem neuen Standard für wirtschaftliches und zuverlässiges Schrumpfen. Entwickelt für den industriellen 24/7-Dauerbetrieb (Betriebsart S1) , erreicht das Gerät bis zu 600 °C und ist damit optimal geeignet für anspruchsvolle Anwendungen im Kabel- und Bauteilschrumpfen. Maximale Effizienz im Dauerbetrieb Robuste Bauweise „Made in Germany“ für den störungsfreien 3-Schicht-Betrieb – ideal für Unternehmen mit hohen Produktionsanforderungen. Hohe Lebensdauer Dank hochwertiger Komponenten und bewährter Technik sind viele unserer Anlagen seit über 20 Jahren zuverlässig im Einsatz. Wartungsarm & zuverlässig Mit über 95 % Verfügbarkeit profitieren Sie von einem minimalen Wartungsaufwand und einer einfachen Ersatzteilbeschaffung. Flexibel & zukunftssicher Das Schrumpfgerät ist konfigurierbar und nachrüstbar – somit optimal an neue Produktionsanforderungen anpassbar. Einfache Bedienung Intuitive Benutzerführung sorgt für einen geringen Schulungsaufwand und schnelle Integration in bestehende Prozesse. Schonendes Schrumpfen ohne Überhitzung Die gleichmäßige Wärmeverteilung schützt Kabel und Bauteile – keine punktuelle Hitze wie bei Infrarotstrahlung. Maximale Temperatur: bis 600 °C Regelbare Transportgeschwindigkeit: 0,3–2,0 m/min Teilautomatisierung: für schnelle, gleichmäßige Erwärmung Industriequalität: für anspruchsvolle Produktionsumgebungen Energieeffizient & elektrisch beheizt 👉 Jetzt Kontakt aufnehmen','—',NULL,'Stück',ARRAY['Standardausführung']::text[],ARRAY[]::text[],ARRAY['Schrumpfofen']::text[],ARRAY['Schrumpfen & Verarbeiten','Konfektion & Ablängen','Serien- & Werkstattfertigung','Montage']::text[],'[{"label":"Besonderheiten","value":"Schrumpfofen"}]'::jsonb,NULL,'/bit/products/durchlauf-schrumpfgeraet.png','Durchlauf-Schrumpfgerät','published',112) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
