insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpf-foehn-heissluftgeblaese-hg-2320-e','verarbeitungsgeraete','HG 2320 E','Steinel HG 2320 E Heißluftgebläse (Heißluft-Föhn)','HG 2320 E','Elektronisch geregeltes Professional-Heißluftgebläse mit LCD-Display und LOC-Funktion Leistung: 2300 Watt Temperaturbereich 80° C – 650 °C stufenlos regelbar LOC-Funktion (Verriegelung der Einstellungen für einen sicheren Arbeitsprozess) Luftmengenregulierung stufenlos (150-500 l/min) 4 Programme abspeicherbar Schutz durch Resthitzeanzeige Länge Netzkabel 3,00m, einfach austauschbar über Kabelschacht Dieses Heißluftgebläse (Heißluft-Föhn) ist ideal geeignet für die Verarbeitung unserer Schrumpfschläuche.','—',NULL,'Stück',ARRAY['Standardausführung']::text[],ARRAY[]::text[],ARRAY['Heißluftgebläse']::text[],ARRAY['Schrumpfen & Verarbeiten','Konfektion & Ablängen','Serien- & Werkstattfertigung','Montage']::text[],'[{"label":"Besonderheiten","value":"Heißluftgebläse"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/HG-2320-E.pdf','/bit/products/schrumpf-foehn-heissluftgeblaese-hg-2320-e.jpg','Heißluftgebläse HG 2320 E','published',118) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpfofen','verarbeitungsgeraete','Schrumpfofen','Schrumpfofen','Heißluftgebläse, Heißschneidegeräte, Zangen & Schrumpfanlagen','Der Schrumpfofen ist die ideale Lösung für eine effiziente und gleichmäßige Wärmebehandlung von verschiedenen Materialien. Mit der Möglichkeit, Temperatur und Transportgeschwindigkeit genau zu regulieren, bieten unsere Schrumpfofen-Systeme höchste Präzision und Flexibilität für eine Vielzahl von Anwendungen. Produkt- & Prozessbeispiele Trocknung von Kupferlitzen Vorwärmen von Metallteilen Tempern von Gummi-/Kunststoff-Teilen Verbacken von Blechpaketen Schrumpffolien Wärmebehandlung von Batteriebechern Tempern von Gummi-/Metall-Teilen Warenträger für Schrumpfschläuche Schrumpfschläuche für präzise Anwendungen Ihre Vorteile auf einen Blick Energieeffizienz : Nutzen Sie den Schrumpfofen, um die Energieverbrauchskosten zu senken und die Wärmebehandlung effizienter zu gestalten. Schnelle & gleichmäßige Erwärmung : Dank der fortschrittlichen Technologie wird eine gleichmäßige Temperaturverteilung garantiert, wodurch Ihre Produkte in kürzester Zeit perfekt behandelt werden. Keine Überhitzung der Produkte : Der Schrumpfofen stellt sicher, dass Ihre Produkte nie überhitzen und somit ihre Qualität bewahren. Lange Lebenserwartung : Robuste Materialien und eine durchdachte Bauweise garantieren eine lange Lebensdauer des Schrumpfofens, auch bei 24/7-Dauerbetrieb. Dauerbetrieb 24/7 : Der Schrumpfofen ist für den Dauerbetrieb geeignet, was ihn besonders zuverlässig und vielseitig einsetzbar macht. Geringer Wartungsaufwand : Minimierter Wartungsaufwand sorgt dafür, dass Ihr Schrumpfofen über Jahre hinweg reibungslos funktioniert. Konfigurierbar/erweiterbar : Die modulare Bauweise ermöglicht es, den Schrumpfofen genau an Ihre individuellen Anforderungen anzupassen und zu erweitern. Leichte & intuitive Bedienung : Die benutzerfreundliche Steuerung ermöglicht eine einfache Handhabung, auch ohne tiefgehende technische Kenntnisse. Technische Daten des Schrumpfofens Unser Schrumpfofen bietet eine präzise Steuerung der Temperatur und der Transportgeschwindigkeit. Die wichtigsten technischen Daten im Überblick: Maximale Temperatur : Bis zu 250°C ± 5°C Transportgeschwindigkeit : Regelbar von 0,5 – 4,0 m/min Kühlung : Optimierte Kühlfunktionen für eine kontrollierte Abkühlung der Produkte nach der Wärmebehandlung Zuluft & Abluft : Effiziente Luftzirkulation für gleichmäßige Erwärmung und Kühlung Ofenzone : Gleichmäßige Wärmeverteilung und optimale Platzierung für verschiedene Materialien Vielseitige Einsatzmöglichkeiten des Schrumpfofens Unser Schrumpfofen ist für zahlreiche Anwendungen in der Industrie geeignet. Von der Wärmebehandlung von Schrumpffolien bis hin zum Tempern von Gummi-/Metall-Teilen – der Schrumpfofen bietet eine präzise und schnelle Lösung für Ihre Produktionsanforderungen. Warum der Schrumpfofen die ideale Wahl ist Der Schrumpfofen stellt die perfekte Lösung für Ihre Wärmebehandlungsprozesse dar. Mit innovativen Funktionen, hoher Energieeffizienz und benutzerfreundlicher Bedienung ist er die erste Wahl für Unternehmen, die höchste Qualität und Präzision in ihren Produktionsprozessen benötigen. Kontaktieren Sie uns noch heute, um mehr über unsere Schrumpfofen-Lösungen zu erfahren und wie sie Ihre Produktionsprozesse verbessern können!','—',NULL,'Stück',ARRAY['Standardausführung']::text[],ARRAY[]::text[],ARRAY['Schrumpfofen']::text[],ARRAY['Schrumpfen & Verarbeiten','Konfektion & Ablängen','Serien- & Werkstattfertigung','Montage']::text[],'[{"label":"Besonderheiten","value":"Schrumpfofen"}]'::jsonb,NULL,'/bit/products/schrumpfofen.png','Schrumpfofen','published',119) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpfschlauch-drucker','verarbeitungsgeraete','Schrumpfschlauch-Drucker CAB SQUIX 4 M','Schrumpfschlauch-Drucker CAB SQUIX 4 M','Heißluftgebläse, Heißschneidegeräte, Zangen & Schrumpfanlagen','Die professionellen SQUIX-Industriedrucker kommen in einem breiten Anwendungsgebiet zum Einsatz. Ihre Entwicklung ist konsequent auf eine einfache und intuitive Bedienung und hohe Zuverlässigkeit ausgerichtet. Die Druckmechanik und das Gehäuse sind aus hochwertigen Materialien gefertigt und perfekt in Form und Funktion aufeinander abgestimmt. Umfangreiche Peripherie und Software ermöglichen kundenspezifische Lösungen. Ob im Stand-alone-Einsatz, als PC-Anwendung oder in einem Netzwerk – die robusten SQUIX-Drucker sind jeder Anforderung gewachsen.','—',NULL,'Stück',ARRAY['Standardausführung']::text[],ARRAY[]::text[],ARRAY['Schrumpfschlauch-Drucker']::text[],ARRAY['Schrumpfen & Verarbeiten','Konfektion & Ablängen','Serien- & Werkstattfertigung','Montage']::text[],'[{"label":"Besonderheiten","value":"Schrumpfschlauch-Drucker"}]'::jsonb,NULL,'/bit/products/schrumpfschlauch-drucker.jpg','Schrumpfschlauch-Drucker CAB SQUIX 4 M','published',120) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
