insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpf-aufteilkappen-bbos','weitere-produkte','BBOS','Schrumpf-Aufteilkappen aus Polyolefin','BBOS · Polyolefin','BBOS Schrumpf-Aufteilkappen eignen sich zur Isolierung und Abdichtung von Mehrleiterkabeln und Leitungsabzweigungen. Die Schrumpf-Aufteilkappen sind für den Einsatz bei 2-, 3-, 4-, und 5-adrigen Kabel und Leitungen geeignet. Der innenseitige thermoplastische Kleber schmilzt beim Erhitzen und dichtet zuverlässig ab.','Polyolefin','-55 °C bis 110 °C','Stück',ARRAY['Standardausführung']::text[],ARRAY['Schwarz']::text[],ARRAY['Schrumpf-Aufteilkappe']::text[],ARRAY['Kabelverbindung','Kabelbefestigung','Reparatur & Wartung','Vormontage']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"Schrumpf-Aufteilkappe"},{"label":"Betriebstemperatur min.","value":"-55 °C"},{"label":"Betriebstemperatur max.","value":"110 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BBOS.pdf','/bit/products/schrumpf-aufteilkappen-bbos.jpg','Schrumpf-Aufteilkappen aus Polyolefin','published',127) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpf-endkappen','weitere-produkte','Schrumpf Endkappen','Schrumpf Endkappen','Polyolefin','Schrumpf-Endkappen sind ideal zur Abdichtung von Kabel- und Rohrenden gegen Feuchtigkeit und andere Medien geeignet. Die Endkappen sind innen mit einem thermoplastischen Schmelzkleber beschichtet. Das verwendete Material ist UV- und witterungsbeständig und kann daher sehr gut im Außenbereich eingesetzt werden. Schrumpf Endkappen: Effizienter Schutz für vielfältige Anwendungen Schrumpfkappen bieten eine zuverlässige und effektive Lösung für den Schutz und die Isolation von Kabelenden. Sie sind sehr schnell mittels Heißluftfön oder offener Flamme zu verarbeiten. Innenkleber für zusätzlichen Schutz Der eingebrachte thermoplastische Innenkleber sorgt für einen feuchtigkeitsdichten Schutz, so dass die Endkappen auch hervorragend für den Außeneinsatz, z.B. für das Umschrumpfen von Seilenden geeignet ist. Hohe Schrumpfrate für flexible Anwendungen Die Schrumpf Endkappen zeichnen sich durch ihre hohe Schrumpfrate aus und bieten dadurch eine passgenaue und sichere Abdeckung der zu umschrumpfenden Komponenten. BIT bietet Schrumpf Endkappen bis zu einem Durchmesser von 500mm an. Für druckluftüberwachte Fernmeldekabelanlagen können Sie bei uns auch Schrumpfkappen mit Luftventilen anfragen.','Polyolefin','-40 °C bis +110 °C','Stück',ARRAY['Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm','Ø 120 mm','Ø 150 mm']::text[],ARRAY['Schwarz']::text[],ARRAY['Kleberbeschichtet','Schrumpf-Endkappe']::text[],ARRAY['Kabelverbindung','Kabelbefestigung','Reparatur & Wartung','Vormontage']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"kleberbeschichtet, Schrumpf-Endkappe"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"+110 °C"},{"label":"Durchmesser innen von (mm)","value":"3,00"},{"label":"Durchmesser innen bis (mm)","value":"500,00"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/Schrumpfkappen.pdf','/bit/products/schrumpf-endkappen.jpg','Schrumpf-Endkappen','published',128) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('schrumpfmuffen-blvk','weitere-produkte','BLVK','Schrumpfmuffen','BLVK · Polyolefin','Die Schrumpfmuffen-Sets BLVK sind perfekt für das Verbinden von mehradrigen Kabeln geeignet.','Polyolefin','-55 °C bis +110 °C','Stück',ARRAY['Standardausführung']::text[],ARRAY['Schwarz']::text[],ARRAY['Schrumpfmuffen-Set']::text[],ARRAY['Kabelverbindung','Kabelbefestigung','Reparatur & Wartung','Vormontage']::text[],'[{"label":"Werkstoff","value":"Polyolefin"},{"label":"Besonderheiten","value":"Schrumpfmuffen-Set"},{"label":"Betriebstemperatur min.","value":"-55 °C"},{"label":"Betriebstemperatur max.","value":"+110 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/BLVK.pdf','/bit/products/schrumpfmuffen-blvk.jpg','mittelwandige Schrumpfschläuche','published',129) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('spiralschlauch-gst','weitere-produkte','GST','GST Spiralschlauch','GST · LD-PE','Der GST Spiralschlauch wird zum Bündeln von Kabeln und Leitungen verwendet. Durch den durchlaufenden Spiralschnitt ist die Abzweigung an jedem beliebigen Punkt des Spiralschlauches möglich. GST Spiralschläuche sind konzipiert, um Kabel und Leitungen zu bündeln und gleichzeitig vor mechanischen Beschädigungen zu schützen. Sie bieten eine hohe Flexibilität und können zudem wiederverwendet werden. Wie installiert man einen Spiralschlauch? Die Installation von GST Spiralschläuchen erfordert kein Werkzeug und ist unkompliziert: Schritt 1: Ermitteln Sie den Außendurchmesser Ihres Kabelbündels und wählen Sie dann den passenden Durchmesser des Spiralschlauchs. Schritt 2: Wählen Sie die gewünschte Länge des Kabelschutzes oder kürzen Sie ihn bei Bedarf. Wickeln Sie dann den Spiralschlauch um Ihr Kabelbündel, indem Sie sie ähnlich wie Isolierband von einem Ende zum anderen anbringen. Schritt 3: Wenn Sie einzelne Kabel aus dem Spiralschlauch herausführen möchten, tun Sie dies während des Wickelns an der entsprechenden Stelle. Wenn Sie dies zu einem späteren Zeitpunkt tun möchten, können Sie den Schlauch an die gewünschte Stelle zurückwickeln.','LD-PE','-50 °C bis +90 °C','Stück',ARRAY['Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm','Ø 120 mm','Ø 150 mm']::text[],ARRAY['Schwarz','Natur']::text[],ARRAY['Flexibel','Spiralschlauch']::text[],ARRAY['Kabelverbindung','Kabelbefestigung','Reparatur & Wartung','Vormontage']::text[],'[{"label":"Werkstoff","value":"LD-PE"},{"label":"Besonderheiten","value":"flexibel, Spiralschlauch"},{"label":"Betriebstemperatur min.","value":"-50 °C"},{"label":"Betriebstemperatur max.","value":"+90 °C"},{"label":"Durchmesser innen von (mm)","value":"3,0"},{"label":"Durchmesser innen bis (mm)","value":"150"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/GST.pdf','/bit/products/spiralschlauch-gst.jpg','Spiralschlauch Spiralband','published',130) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('spiralschlauch-gst-ptfe','weitere-produkte','GST PTFE','Spiralschlauch aus PTFE','GST PTFE · PTFE','Der Spiralschlauch wird zum Bündeln von Kabeln und Leitungen verwendet. Durch den durchlaufenden Spiralschnitt ist die Abzweigung an jedem beliebigen Punkt möglich. PTFE bietet eine sehr gute Beständigkeit gegenüber vielen Chemikalien und hohen Temperaturen.','PTFE','-67 °C bis +260 °C','Stück',ARRAY['Ø 2 mm','Ø 2,5 mm','Ø 3 mm','Ø 4 mm','Ø 5 mm','Ø 6 mm','Ø 8 mm','Ø 10 mm','Ø 12 mm','Ø 16 mm','Ø 20 mm','Ø 25 mm','Ø 30 mm','Ø 40 mm','Ø 50 mm','Ø 65 mm','Ø 80 mm','Ø 100 mm','Ø 120 mm','Ø 150 mm']::text[],ARRAY['Natur']::text[],ARRAY['Hohe chemische Beständigkeit','Hohe Temperaturbeständigkeit','Spiralschlauch']::text[],ARRAY['Kabelverbindung','Kabelbefestigung','Reparatur & Wartung','Vormontage']::text[],'[{"label":"Werkstoff","value":"PTFE"},{"label":"Besonderheiten","value":"hohe chemische Beständigkeit, hohe Temperaturbeständigkeit, Spiralschlauch"},{"label":"Betriebstemperatur min.","value":"-67 °C"},{"label":"Betriebstemperatur max.","value":"+260 °C"},{"label":"Durchmesser innen von (mm)","value":"1,6"},{"label":"Durchmesser innen bis (mm)","value":"150"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/GST-PTFE.pdf','/bit/products/spiralschlauch-gst-ptfe.jpg','Spiralschlauch GST PTFE','published',131) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_