insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('technische-schlaeuche-aufschiessschlaeuche','weitere-produkte','Technische Schläuche','Griffschläuche und Aufschießschläuche aus Weich-PVC','Technische Schläuche · Weich-PVC','Technische Schläuche – Griffummantelung – Griffschläuche – Aufschießschläuche Für die Fertigung von Griffschlauch-Lösungen oder Aufschießschläuchen setzen wir gerne die Anforderungen unserer Kunden nach technischen Möglichkeiten um. Griffschläuche: robuste und strapazierfähige Griffummantelungen Je nach Anwendung können die Griffschläuche glatt oder gerieft und in Dimensionen und Shorehärten nach Kundenvorgabe hergestellt werden. Die hohe Qualität der BIT Griff- und Aufschießschläuche zeichnet sich durch eine angenehme Haptik und eine sehr hohe Widerstandsfähigkeit aus. Teilen Sie unserem Vertriebsteam Ihre Anforderungen mit und lassen Sie sich ein unverbindliches Angebot erstellen, das auf Ihre Bedürfnisse zugeschnitten ist.','Weich-PVC',NULL,'Stück',ARRAY['Standardausführung']::text[],ARRAY['Schwarz','Rot','Weiß','Blau','Gelb','Grün','Andere auf Anfrage']::text[],ARRAY['Aufschießschläuche','Griffschläuche','Technische Schläuche']::text[],ARRAY['Kabelverbindung','Kabelbefestigung','Reparatur & Wartung','Vormontage']::text[],'[{"label":"Werkstoff","value":"Weich-PVC"},{"label":"Besonderheiten","value":"Aufschießschläuche, Griffschläuche, Technische Schläuche"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2020/03/Technische-Schlaeuche.pdf','/bit/products/technische-schlaeuche-aufschiessschlaeuche.jpg','Technische Schläuche','published',133) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=exclu