insert into bit_products (slug,category_id,code,name,tagline,description,material,temperature,unit,sizes,colors,features,applications,tech,datasheet_url,image_path,image_alt,status,sort_order) values ('solar-und-kantenclips','kantenclips','Solar- und Kantenclips','Solar- und Kantenclips','Polyamid 6.6 HS','Unsere Kantenclips sind eine robuste und langlebige Lösung zur Befestigung von Kabeln, Drähten und Rohren an Kunststoff- und Metallprofilen. Sie bestehen aus hochwertigem Polyamid 6.6 HS, einem Material, das besonders beständig gegen hohe Temperaturen, Chemikalien, UV-Strahlung und Feuchtigkeit ist. Die Kantenclips sind einfach zu montieren und stellen eine feste Verbindung her. Sie sind in unterschiedlichen Größen und Ausführungen erhältlich. Kantenclips sind die perfekte Wahl für den Einsatz in der Fotovoltaik-Montage, in der Automobil- und Elektronikindustrie, im Maschinen- und Schiffsbau und in vielen anderen Branchen. Mit ihnen lassen sich Kabel und Drähte schnell und einfach ordnen und fixieren. So sorgen Sie für eine übersichtliche und sichere Verlegung von Kabeln und Drähten, z. B. an PV-Modulen.','Polyamid 6.6 HS','-40 °C bis +120 °C','Stück',ARRAY['Standardausführung']::text[],ARRAY['Schwarz']::text[],ARRAY['Hitzebeständig','Schlagfest','UV-beständig']::text[],ARRAY['Photovoltaik-Montage','Leitungsführung an Blechkanten','Modulrahmen-Befestigung','Werkzeuglose Montage']::text[],'[{"label":"Werkstoff","value":"Polyamid 6.6 HS"},{"label":"Besonderheiten","value":"hitzebeständig, Schlagfest, UV-beständig"},{"label":"Betriebstemperatur min.","value":"-40 °C"},{"label":"Betriebstemperatur max.","value":"+120 °C"}]'::jsonb,'https://www.bit-gmbh.de/wp-content/uploads/2023/01/Solar-und-Kantenclips.pdf','/bit/products/solar-und-kantenclips.jpg','Solarclips','published',135) on conflict (slug) do update set category_id=excluded.category_id,code=excluded.code,name=excluded.name,tagline=excluded.tagline,description=excluded.description,material=excluded.material,temperature=excluded.temperature,unit=excluded.unit,sizes=excluded.sizes,colors=excluded.colors,features=excluded.features,applications=excluded.applications,tech=excluded.tech,datasheet_url=excluded.datasheet_url,image_path=excluded.image_path,image_alt=excluded.image_alt;
